// parts.js
var _partsTab='inventory',_partsData={inventory:[],invoices:[],manuals:[],crossref:[],orders:[]},_editingPart=null,_machinesList=[],_scanLineCount=0,_partsInvFilter='',_xrVendors=[];
// Machines list is per-COMPANY, stored on the server so every user sees the same list.
// Render functions call loadMachines() synchronously at the top. We keep a 5-second
// cache to keep those calls cheap and avoid a re-render loop when the API return
// triggers another render pass. saveMachines also bumps the cache timestamp to freeze
// it with local state while the POST is in flight.
var _machinesFetchedAt=0,_machinesLoadInFlight=false;
function loadMachines(cb){
  if(Date.now()-_machinesFetchedAt<5000){if(cb)cb();return;}
  if(_machinesLoadInFlight){if(cb)setTimeout(function(){loadMachines(cb);},120);return;}
  _machinesLoadInFlight=true;
  apiCall('GET','/api/parts?action=get_machines').then(function(rows){
    var serverList=Array.isArray(rows)?rows:[];
    // One-time migration: if the server is empty but this browser has legacy localStorage machines, upload them.
    if(serverList.length===0){
      var legacy=[];
      try{legacy=JSON.parse(localStorage.getItem('parts_machines')||'[]');}catch(e){}
      if(Array.isArray(legacy)&&legacy.length>0){
        _machinesList=legacy;
        apiCall('POST','/api/parts?action=save_machines',{machines:legacy}).then(function(){
          try{localStorage.removeItem('parts_machines');}catch(e){}
        }).catch(function(){});
      }else{_machinesList=[];}
    }else{_machinesList=serverList;}
    _machinesFetchedAt=Date.now();
    _machinesLoadInFlight=false;
    if(cb)cb();
    // NOTE: do NOT auto-re-render the current tab here. partsAddPartForm / partsAdjustForm
    // / partsUploadManualForm all call loadMachines() at their top, and they REPLACE the
    // parts-panel with their own form markup. An auto-re-render fires ~300ms later and
    // clobbers the form with the inventory list. Callers that need to react to the fresh
    // list should pass an explicit cb. Stale labels in _machinesList for a sub-second is
    // an acceptable trade for not eating user-visible sub-forms.
  }).catch(function(){_machinesLoadInFlight=false;if(cb)cb();});
}
function saveMachines(){_machinesFetchedAt=Date.now();apiCall('POST','/api/parts?action=save_machines',{machines:_machinesList}).catch(function(){});}
function buildPartsWidget(){var wt=document.getElementById('widget-tabs'),wc=document.getElementById('widget-content');var tabs=['inventory','troubleshoot','invoices','manuals','crossref','orders','machines'];var labels={inventory:'Inventory',invoices:'Invoices',manuals:'Manuals',crossref:'Cross-Ref',orders:'Orders',machines:'Machines',troubleshoot:'🔧 Troubleshoot'};wt.innerHTML=tabs.map(function(t){return '<button class="wtab" onclick="partsShowTab(\''+t+'\')" id="ptab-'+t+'" style="padding:6px 12px;border:none;background:transparent;cursor:pointer;font-size:.78rem;border-bottom:2px solid transparent;color:#94a3b8">'+labels[t]+'</button>';}).join('');wc.innerHTML='<div id="parts-panel" style="padding:0"></div>';loadMachines();partsInit();}
function partsInit(){apiCall('GET','/api/parts?action=init_parts_db').then(function(){partsShowTab('inventory');}).catch(function(){partsShowTab('inventory');});}
function partsShowTab(tab){_partsTab=tab;['inventory','invoices','manuals','crossref','orders','machines','troubleshoot'].forEach(function(t){var b=document.getElementById('ptab-'+t);if(b){b.style.borderBottomColor=t===tab?'#1a3a6b':'transparent';b.style.color=t===tab?'#1a3a6b':'#94a3b8';b.style.fontWeight=t===tab?'600':'400';b.style.background='transparent';}});var panel=document.getElementById('parts-panel');if(!panel)return;if(tab==='machines'){partsRenderMachines();return;}if(tab==='troubleshoot'){partsRenderTroubleshoot();return;}panel.innerHTML='<div style="padding:20px;text-align:center;color:#94a3b8">Loading...</div>';var actions={inventory:'get_parts',invoices:'get_invoices',manuals:'get_manuals',crossref:'get_cross_ref',orders:'get_parts_orders'};var endpoint=tab==='manuals'?'/api/manuals?action=get_manuals':'/api/parts?action='+actions[tab];apiCall('GET',endpoint).then(function(data){_partsData[tab]=Array.isArray(data)?data:[];var r={inventory:partsRenderInventory,invoices:partsRenderInvoices,manuals:partsRenderManuals,crossref:partsRenderCrossRef,orders:partsRenderOrders};if(r[tab])r[tab]();}).catch(function(){document.getElementById('parts-panel').innerHTML='<div style="padding:20px;color:#ef4444">Error loading data</div>';});}
window.partsShowTab=partsShowTab;
var CARD='background:#fff;border-radius:10px;padding:14px;margin-bottom:10px;box-shadow:0 1px 4px rgba(0,0,0,.08)';
var BTN='padding:6px 12px;border-radius:6px;border:none;cursor:pointer;font-size:.78rem;font-weight:600';
var BTN_P=BTN+';background:#1a3a6b;color:#fff';
var BTN_S=BTN+';background:#6366f1;color:#fff';
var BTN_E='padding:3px 9px;border-radius:5px;border:none;cursor:pointer;font-size:.73rem;background:#e0e7ff;color:#3730a3';
var BTN_D='padding:3px 9px;border-radius:5px;border:none;cursor:pointer;font-size:.73rem;background:#fee2e2;color:#b91c1c;margin-left:5px';
var BTN_A='padding:3px 9px;border-radius:5px;border:none;cursor:pointer;font-size:.73rem;background:#fef3c7;color:#92400e;margin-right:5px';
var INP='width:100%;padding:8px;border:1px solid #e2e8f0;border-radius:6px;font-size:.83rem;margin-bottom:8px;box-sizing:border-box';
function machineTagOptions(sel){var o='<option value="shop_stock"'+(!sel||sel==='shop_stock'?' selected':'')+'>Shop Stock</option>';_machinesList.forEach(function(m){o+='<option value="'+m.id+'"'+(sel===m.id?' selected':'')+'>'+m.name+'</option>';});return o;}
function machineFilterOptions(sel){sel=sel||'';var o='<option value=""'+(sel===''?' selected':'')+'>All Locations</option>';o+='<option value="shop_stock"'+(sel==='shop_stock'?' selected':'')+'>Shop Stock</option>';_machinesList.forEach(function(m){o+='<option value="'+m.id+'"'+(sel===m.id?' selected':'')+'>'+m.name+'</option>';});return o;}
function machineTagLabel(v){if(!v||v==='shop_stock')return '<span style="background:#dbeafe;color:#1d4ed8;padding:2px 8px;border-radius:10px;font-size:.72rem">Shop Stock</span>';var m=_machinesList.find(function(x){return x.id===v;});return m?'<span style="background:#dcfce7;color:#15803d;padding:2px 8px;border-radius:10px;font-size:.72rem">'+m.name+'</span>':'<span style="background:#f1f5f9;color:#64748b;padding:2px 8px;border-radius:10px;font-size:.72rem">'+v+'</span>';}
function partsRenderInventory(){loadMachines();var panel=document.getElementById('parts-panel');var html='<div style="padding:14px"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px"><span style="font-weight:700;font-size:.95rem">Parts Inventory</span><div><button style="'+BTN_S+';margin-right:6px" onclick="partsFindParts()">Find</button><button style="'+BTN_P+'" onclick="partsAddPartForm(-1)">+ Add Part</button></div></div><div id="inv-stats"></div><div style="display:flex;gap:6px;margin-bottom:10px"><input type="text" id="inv-stock-search" placeholder="Search part #, description..." style="flex:3;'+INP+';margin-bottom:0" oninput="partsApplyInvFilters()"><select id="inv-filter" onchange="partsApplyInvFilters()" style="flex:2;'+INP+';margin-bottom:0">'+machineFilterOptions(_partsInvFilter)+'</select></div><div id="inv-list"></div></div>';panel.innerHTML=html;partsApplyInvFilters();}
function partsInvRow(p,i){var qty=parseInt(p.quantity)||0;var avg=parseFloat(p.avg_cost||p.unit_cost||0);var tot=parseFloat(p.total_value||qty*avg);var pnEsc=(p.part_number||'').replace(/'/g,"\\'");var descEsc=(p.description||'').replace(/'/g,"\\'");var vendorCount=0;try{var vs=p.custom_vendors;if(typeof vs==='string'&&vs)vs=JSON.parse(vs);if(Array.isArray(vs))vendorCount=vs.length;}catch(e){vendorCount=0;}var customBadge=p.is_custom?' <span style="background:#e0e7ff;color:#3730a3;padding:1px 6px;border-radius:10px;font-size:.64rem;font-weight:600;letter-spacing:.04em">CUSTOM</span>':'';var quoteBtn=p.is_custom?'<button style="'+BTN_S+';padding:3px 8px;font-size:.7rem" onclick="partsQuoteAllVendors('+i+')" title="'+(vendorCount?'Email '+vendorCount+' vendor'+(vendorCount===1?'':'s')+' for a quote':'No vendors configured yet — edit the part to add them')+'">Quote</button> ':'';return '<tr style="border-bottom:1px solid #e2e8f0"><td style="padding:6px 10px">'+(p.part_number?'<a href="#" onclick="partsGotoCrossRefForPart(\''+pnEsc+'\',\''+descEsc+'\');return false" style="font-family:monospace;color:#2563eb;text-decoration:underline;font-weight:600">'+p.part_number+'</a>':'<span style="color:#94a3b8">—</span>')+'</td><td style="padding:6px 10px">'+(p.description||'')+customBadge+'</td><td style="padding:4px 10px;text-align:right"><input type="number" min="0" step="1" value="'+qty+'" data-part-id="'+(p.id||'')+'" data-orig="'+qty+'" onchange="partsInlineAdjust(this)" title="Edit on-hand qty. Logs an adjustment as \'manual\'." style="width:58px;padding:4px 6px;border:1px solid #e2e8f0;border-radius:5px;font-size:.76rem;text-align:right;font-weight:600;background:#fff"></td><td style="padding:6px 10px;text-align:right">$'+avg.toFixed(2)+'</td><td style="padding:6px 10px;text-align:right;color:#166534;font-weight:600">$'+tot.toFixed(2)+'</td><td style="padding:6px 10px">'+machineTagLabel(p.machine_tag||'')+'</td><td style="padding:6px 10px;white-space:nowrap;text-align:right">'+quoteBtn+'<button style="'+BTN_A+';padding:3px 8px;font-size:.7rem" onclick="partsAdjustForm('+i+')">Adjust</button> <button style="'+BTN_E+';padding:3px 8px;font-size:.7rem" onclick="partsAddPartForm('+i+')">Edit</button> <button style="'+BTN_D+';padding:3px 8px;font-size:.7rem" onclick="partsDelPart('+i+')">Del</button></td></tr>';}
function partsQuoteAllVendors(i){var p=_partsData.inventory[i];if(!p){alert('Part not found');return;}var vendors=[];try{if(Array.isArray(p.custom_vendors))vendors=p.custom_vendors;else if(typeof p.custom_vendors==='string'&&p.custom_vendors)vendors=JSON.parse(p.custom_vendors);}catch(e){vendors=[];}if(!vendors.length){alert('No vendors configured for this part. Edit the part to add vendors.');return;}window._qvVendors=vendors;window._qvPart=p;var overlay=document.createElement('div');overlay.id='qv-overlay';overlay.style.cssText='position:fixed;inset:0;background:rgba(0,0,0,.5);z-index:9999;display:flex;align-items:center;justify-content:center;padding:20px';overlay.innerHTML='<div style="background:#fff;border-radius:12px;padding:20px;max-width:560px;width:100%;max-height:85vh;overflow-y:auto;box-shadow:0 20px 60px rgba(0,0,0,.3)"><div style="font-weight:700;font-size:1rem;margin-bottom:4px">Request Quotes</div><div style="font-size:.86rem;color:#334155;margin-bottom:4px">'+(p.description||p.part_number||'Custom Part')+'</div><div style="color:#64748b;font-size:.78rem;margin-bottom:12px">'+vendors.length+' vendor'+(vendors.length===1?'':'s')+' — each gets their own part number in the email.</div><label style="font-size:.78rem;color:#64748b">Quantity needed</label><input type="number" id="qv-qty" min="1" value="1" style="'+INP+';margin-bottom:12px" oninput="partsRenderQuoteVendors()"><div id="qv-vendors"></div><div style="display:flex;gap:8px;justify-content:flex-end;margin-top:12px;padding-top:12px;border-top:1px solid #e2e8f0"><button style="'+BTN+';background:#f1f5f9;color:#334155" onclick="document.getElementById(\'qv-overlay\').remove()">Close</button><button style="'+BTN_P+'" onclick="partsQuoteAllOpen()">Open All '+vendors.length+' Emails</button></div></div>';document.body.appendChild(overlay);partsRenderQuoteVendors();}
function partsRenderQuoteVendors(){var vs=window._qvVendors||[];var list=document.getElementById('qv-vendors');if(!list)return;list.innerHTML=vs.map(function(v,i){var hasEmail=!!(v.contact_email||'').trim();var canSend=hasEmail&&(v.vendor_part_number||'').trim();return '<div style="background:#f8fafc;border-radius:8px;padding:10px;margin-bottom:6px"><div style="font-weight:600;font-size:.85rem;color:#1a3a6b">'+(v.vendor_name||'Vendor')+'</div>'+(v.contact_name?'<div style="color:#64748b;font-size:.76rem">👤 '+v.contact_name+'</div>':'')+(hasEmail?'<div style="color:#64748b;font-size:.76rem;word-break:break-all">✉️ '+v.contact_email+'</div>':'<div style="color:#dc2626;font-size:.76rem">⚠ no email</div>')+'<div style="color:#334155;font-size:.76rem;font-family:monospace">Part # '+((v.vendor_part_number||'').trim()||'<span style="color:#dc2626">not set</span>')+'</div>'+(v.notes?'<div style="color:#94a3b8;font-size:.72rem;margin-top:2px">'+v.notes+'</div>':'')+'<button style="'+(canSend?BTN_P:BTN)+';padding:3px 10px;font-size:.74rem;margin-top:6px'+(canSend?'':';background:#f1f5f9;color:#94a3b8;cursor:not-allowed')+'" '+(canSend?'':'disabled')+' onclick="partsQuoteSingleVendor('+i+')">Send Quote Request</button></div>';}).join('');}
function partsQuoteSingleVendor(vIdx){var v=(window._qvVendors||[])[vIdx];var p=window._qvPart;if(!v||!p)return;var qty=parseInt((document.getElementById('qv-qty')||{}).value)||1;window.open(partsBuildQuoteMailto(p,v,qty),'_blank');}
function partsQuoteAllOpen(){var p=window._qvPart;var vs=window._qvVendors||[];if(!p||!vs.length)return;var valid=vs.filter(function(v){return (v.contact_email||'').trim()&&(v.vendor_part_number||'').trim();});if(!valid.length){alert('No vendors have both an email and a part number set.');return;}var qty=parseInt((document.getElementById('qv-qty')||{}).value)||1;if(valid.length>3&&!confirm('Open '+valid.length+' quote emails? Your browser may block popups — enable them for this site if it asks.'))return;valid.forEach(function(v,i){setTimeout(function(){window.open(partsBuildQuoteMailto(p,v,qty),'_blank');},i*350);});}
function partsBuildQuoteMailto(p,v,qty){var partNum=(v.vendor_part_number||p.part_number||'').trim();var desc=(p.description||p.part_number||'Custom Part').trim();var subject='Quote Request: '+partNum+(qty>1?' — Qty '+qty:'');var greeting=(v.contact_name||'').trim()?'Hello '+v.contact_name.trim():'Hello';var body=greeting+',\n\nWe would like to request a quote on the following:\n\n  Item: '+desc+'\n  Your Part Number: '+partNum+'\n  Quantity: '+qty+'\n\nPlease include:\n  • Unit price and any volume discount tiers\n  • Availability and lead time\n  • Shipping options and cost\n  • Payment terms\n\nThanks,\nCooper Battle\nPride of the Pond';return 'mailto:'+(v.contact_email||'').trim()+'?subject='+encodeURIComponent(subject)+'&body='+encodeURIComponent(body);}
function partsInlineAdjust(input){var id=input.dataset.partId;var orig=input.dataset.orig;var newQty=parseInt(input.value);if(!id){alert('Missing part id');input.value=orig;return;}if(isNaN(newQty)||newQty<0){alert('Invalid quantity');input.value=orig;return;}if(newQty===parseInt(orig))return;var origBg=input.style.background;input.style.background='#fef3c7';input.disabled=true;apiCall('POST','/api/parts?action=adjust_part',{id:id,new_quantity:newQty,reason:'manual',notes:'Inline edit: '+orig+' → '+newQty}).then(function(){input.style.background='#dcfce7';input.disabled=false;input.dataset.orig=String(newQty);setTimeout(function(){partsShowTab('inventory');},300);}).catch(function(e){input.style.background='#fee2e2';input.disabled=false;input.value=orig;alert('Error: '+((e&&e.message)||'unknown'));});}
function partsApplyInvFilters(){var q=((document.getElementById('inv-stock-search')||{}).value||'').trim().toLowerCase();var filter=((document.getElementById('inv-filter')||{}).value)||'';_partsInvFilter=filter;var items=_partsData.inventory;var f=items.filter(function(p){if(filter){var pt=p.machine_tag||'shop_stock';if(pt!==filter)return false;}if(q){return (p.part_number||'').toLowerCase().indexOf(q)>=0||(p.description||'').toLowerCase().indexOf(q)>=0;}return true;});var totItems=f.reduce(function(s,p){return s+(parseInt(p.quantity)||0);},0);var totVal=f.reduce(function(s,p){return s+(parseFloat(p.total_value||(p.quantity||0)*(p.avg_cost||p.unit_cost||0))||0);},0);var stats=document.getElementById('inv-stats');if(stats)stats.innerHTML='<div style="display:flex;gap:12px;margin-bottom:10px;padding:10px;background:#f0f7ff;border-radius:8px"><div style="flex:1;text-align:center"><div style="font-size:.72rem;color:#64748b">Total Items</div><div style="font-weight:700;color:#1a3a6b;font-size:1rem">'+totItems+'</div></div><div style="flex:1;text-align:center"><div style="font-size:.72rem;color:#64748b">Part Numbers</div><div style="font-weight:700;color:#1a3a6b;font-size:1rem">'+f.length+'</div></div><div style="flex:1;text-align:center"><div style="font-size:.72rem;color:#64748b">Total Inv Value</div><div style="font-weight:700;color:#166534;font-size:1rem">$'+totVal.toFixed(2)+'</div></div></div>';var list=document.getElementById('inv-list');if(!list)return;if(!f.length){list.innerHTML='<div style="text-align:center;color:#94a3b8;padding:30px 0">'+(items.length?'No parts match current filter.':'No parts yet.')+'</div>';return;}list.innerHTML='<div style="overflow-x:auto;background:#fff;border-radius:10px;box-shadow:0 1px 4px rgba(0,0,0,.08)"><table style="width:100%;font-size:.78rem;border-collapse:collapse"><thead><tr style="background:#1a3a6b;color:#fff"><th style="padding:8px 10px;text-align:left;font-weight:600">Part #</th><th style="padding:8px 10px;text-align:left;font-weight:600">Description</th><th style="padding:8px 10px;text-align:right;font-weight:600">On Hand</th><th style="padding:8px 10px;text-align:right;font-weight:600">Avg $/unit</th><th style="padding:8px 10px;text-align:right;font-weight:600">Inv Value</th><th style="padding:8px 10px;text-align:left;font-weight:600">Location</th><th style="padding:8px 10px"></th></tr></thead><tbody>'+f.map(function(p){return partsInvRow(p,items.indexOf(p));}).join('')+'</tbody></table></div>';}
function partsGotoCrossRefForPart(pn,desc){window._crossRefPrefill={part_number:pn||'',description:desc||''};partsShowTab('crossref');}
function partsFindParts(){var q=prompt('Search part number or keyword:');if(q){var inp=document.getElementById('inv-stock-search');if(inp)inp.value=q;partsApplyInvFilters();}}
function partsAddPartForm(editIdx){loadMachines();var p=editIdx>=0?_partsData.inventory[editIdx]:{};var isCustom=!!p.is_custom;var vendors=[];try{if(Array.isArray(p.custom_vendors))vendors=p.custom_vendors;else if(typeof p.custom_vendors==='string'&&p.custom_vendors)vendors=JSON.parse(p.custom_vendors);}catch(e){vendors=[];}document.getElementById('parts-panel').innerHTML='<div style="padding:14px"><div style="display:flex;align-items:center;gap:8px;margin-bottom:14px"><button style="'+BTN+';background:#f1f5f9;color:#334155" onclick="partsShowTab(\'inventory\')">Back</button><span style="font-weight:700;font-size:.95rem">'+(editIdx>=0?'Edit Part':'Add Part')+'</span></div><input type="text" placeholder="Part Number" id="pf-num" style="'+INP+'" value="'+(p.part_number||'')+'"><input type="text" placeholder="Description" id="pf-desc" style="'+INP+'" value="'+(p.description||'')+'"><input type="number" placeholder="Quantity" id="pf-qty" style="'+INP+'" value="'+(p.quantity||'')+'"><input type="number" placeholder="Unit Cost" id="pf-cost" step="0.01" style="'+INP+'" value="'+(p.unit_cost||'')+'"><input type="text" placeholder="Supplier" id="pf-sup" style="'+INP+'" value="'+(p.supplier||'')+'"><input type="text" placeholder="Barcode (optional — for scanning)" id="pf-barcode" style="'+INP+'" value="'+(p.barcode||'')+'"><label style="font-size:.78rem;color:#64748b;display:block;margin-bottom:3px">Assign to Machine or Shop Stock</label><select id="pf-mach" style="'+INP+'">'+machineTagOptions(p.machine_tag||'')+'</select><textarea placeholder="Notes" id="pf-notes" style="'+INP+'resize:vertical;height:60px">'+(p.notes||'')+'</textarea><div style="margin-bottom:10px;padding:10px;background:#f0f7ff;border-radius:8px"><label style="display:flex;align-items:center;gap:8px;cursor:pointer;font-size:.85rem;font-weight:600;color:#1a3a6b"><input type="checkbox" id="pf-is-custom"'+(isCustom?' checked':'')+' onchange="partsToggleCustomSection()"> Custom part (OEM-specific / machine shop)</label><div id="pf-vendors-wrap" style="display:'+(isCustom?'block':'none')+';margin-top:10px"><div style="font-size:.72rem;color:#64748b;margin-bottom:6px">Each vendor can have their own part number. When you click <strong>Quote</strong> on this part in the inventory list, a tailored email is generated for each vendor below.</div><div id="pf-vendors-list"></div><button style="'+BTN+';background:#e0e7ff;color:#3730a3;padding:5px 12px;font-size:.75rem;margin-top:6px" onclick="partsAddVendorRow()">+ Add Vendor</button></div></div><button style="'+BTN_P+';width:100%" onclick="partsSavePart('+editIdx+')">Save Part</button></div>';vendors.forEach(function(v){partsAddVendorRow(v);});}
function partsAddVendorRow(vendor){var v=vendor||{};var list=document.getElementById('pf-vendors-list');if(!list)return;var row=document.createElement('div');row.className='pf-vendor-row';row.style.cssText='background:#fff;border:1px solid #e2e8f0;border-radius:6px;padding:8px;margin-bottom:6px';var iS='padding:6px;border:1px solid #e2e8f0;border-radius:5px;font-size:.76rem;background:#fff';row.innerHTML='<div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;margin-bottom:4px"><input type="text" class="pfv-name" placeholder="Vendor name *" style="'+iS+'" value="'+(v.vendor_name||'').replace(/"/g,'&quot;')+'"><input type="text" class="pfv-contact" placeholder="Contact name" style="'+iS+'" value="'+(v.contact_name||'').replace(/"/g,'&quot;')+'"></div><div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;margin-bottom:4px"><input type="email" class="pfv-email" placeholder="Contact email *" style="'+iS+'" value="'+(v.contact_email||'').replace(/"/g,'&quot;')+'"><input type="text" class="pfv-pn" placeholder="Their part # *" style="'+iS+'" value="'+(v.vendor_part_number||'').replace(/"/g,'&quot;')+'"></div><div style="display:flex;gap:6px;align-items:center"><input type="text" class="pfv-notes" placeholder="Notes (optional)" style="flex:1;'+iS+'" value="'+(v.notes||'').replace(/"/g,'&quot;')+'"><button onclick="this.closest(\'.pf-vendor-row\').remove()" style="padding:4px 8px;border-radius:5px;border:none;cursor:pointer;font-size:.78rem;background:#fee2e2;color:#b91c1c" title="Remove vendor">×</button></div>';list.appendChild(row);}
function partsCollectVendors(){var rows=document.querySelectorAll('.pf-vendor-row');var out=[];rows.forEach(function(r){var name=((r.querySelector('.pfv-name')||{}).value||'').trim();var email=((r.querySelector('.pfv-email')||{}).value||'').trim();var contact=((r.querySelector('.pfv-contact')||{}).value||'').trim();var vPn=((r.querySelector('.pfv-pn')||{}).value||'').trim();var notes=((r.querySelector('.pfv-notes')||{}).value||'').trim();if(name&&email)out.push({vendor_name:name,contact_name:contact,contact_email:email,vendor_part_number:vPn,notes:notes});});return out;}
function partsToggleCustomSection(){var cb=document.getElementById('pf-is-custom');var wrap=document.getElementById('pf-vendors-wrap');if(cb&&wrap)wrap.style.display=cb.checked?'block':'none';}
function partsSavePart(editIdx){var isCustomEl=document.getElementById('pf-is-custom');var data={part_number:document.getElementById('pf-num').value,description:document.getElementById('pf-desc').value,quantity:document.getElementById('pf-qty').value,unit_cost:document.getElementById('pf-cost').value,supplier:document.getElementById('pf-sup').value,machine_tag:document.getElementById('pf-mach').value,barcode:(document.getElementById('pf-barcode')?document.getElementById('pf-barcode').value:''),notes:document.getElementById('pf-notes').value,is_custom:!!(isCustomEl&&isCustomEl.checked),custom_vendors:partsCollectVendors()};var action=editIdx>=0?'update_part':'add_part';if(editIdx>=0)data.id=_partsData.inventory[editIdx].id;apiCall('POST','/api/parts?action='+action,data).then(function(){partsShowTab('inventory');}).catch(function(){alert('Error saving part');});}
function partsDelPart(i){if(!confirm('Delete this part?'))return;apiCall('POST','/api/parts?action=delete_part',{id:_partsData.inventory[i].id}).then(function(){partsShowTab('inventory');}).catch(function(){alert('Error');});}
function partsAdjustForm(i){var p=_partsData.inventory[i];if(!p)return;var overlay=document.createElement('div');overlay.id='adj-overlay';overlay.style.cssText='position:fixed;inset:0;background:rgba(0,0,0,.5);z-index:9999;display:flex;align-items:center;justify-content:center;padding:20px';overlay.innerHTML='<div style="background:#fff;border-radius:12px;padding:20px;max-width:420px;width:100%;box-shadow:0 20px 60px rgba(0,0,0,.3)"><div style="font-weight:700;font-size:.95rem;margin-bottom:4px;color:#1a3a6b">Adjust Quantity</div><div style="font-size:.83rem;color:#334155;margin-bottom:10px">'+(p.part_number||'')+(p.description?' — '+p.description:'')+'</div><div style="background:#f0f7ff;border-radius:8px;padding:8px 12px;font-size:.78rem;color:#475569;margin-bottom:12px">Current: <b>'+(p.quantity||0)+'</b> on hand · Avg cost $'+parseFloat(p.avg_cost||p.unit_cost||0).toFixed(2)+'</div><label style="font-size:.75rem;color:#64748b;display:block;margin-bottom:3px">Set New Quantity <span style="color:#94a3b8">(leave blank to use delta below)</span></label><input type="number" id="adj-new" placeholder="e.g. 12" style="'+INP+'"><label style="font-size:.75rem;color:#64748b;display:block;margin-bottom:3px">Or Delta</label><input type="number" id="adj-delta" placeholder="e.g. -2 for used, +5 for received" style="'+INP+'"><label style="font-size:.75rem;color:#64748b;display:block;margin-bottom:3px">Reason</label><select id="adj-reason" style="'+INP+'"><option value="used">Used</option><option value="received">Received</option><option value="audit">Audit Correction</option><option value="damaged">Damaged</option><option value="other">Other</option></select><textarea id="adj-notes" placeholder="Notes (optional)" style="'+INP+'resize:vertical;height:50px"></textarea><div style="display:flex;gap:8px;justify-content:flex-end;margin-top:6px"><button style="'+BTN+';background:#f1f5f9;color:#334155" onclick="document.getElementById(\'adj-overlay\').remove()">Cancel</button><button style="'+BTN_P+'" onclick="partsSaveAdjust(\''+p.id+'\')">Save</button></div></div>';document.body.appendChild(overlay);}
function partsSaveAdjust(partId){var newQty=document.getElementById('adj-new').value;var delta=document.getElementById('adj-delta').value;if(!String(newQty).trim()&&!String(delta).trim()){alert('Enter a new quantity or delta');return;}var data={id:partId,reason:document.getElementById('adj-reason').value,notes:document.getElementById('adj-notes').value};if(String(newQty).trim()!=='')data.new_quantity=parseInt(newQty,10);else data.delta=parseInt(delta,10);apiCall('POST','/api/parts?action=adjust_part',data).then(function(){var o=document.getElementById('adj-overlay');if(o)o.remove();partsShowTab('inventory');}).catch(function(e){alert('Error: '+(e&&e.message?e.message:'unknown'));});}
function partsRenderInvoices(){var panel=document.getElementById('parts-panel'),items=_partsData.invoices;function invCard(inv,i){var _li=inv.items||inv.line_items||[];var tagHtml='';if(inv.tags&&inv.tags.trim()){tagHtml='<div style="margin-top:4px">'+inv.tags.split(',').map(function(t){return t.trim();}).filter(Boolean).map(function(t){return '<span style="display:inline-block;background:#fef3c7;color:#92400e;padding:1px 7px;border-radius:10px;font-size:.7rem;margin-right:3px">'+t+'</span>';}).join('')+'</div>';}var lineHtml='';if(_li.length){lineHtml='<div style="margin-top:6px;font-size:.78rem;background:#f8fafc;border-radius:6px;padding:6px">'+_li.map(function(li){return '<div style="display:flex;gap:8px;padding:2px 0;border-bottom:1px solid #f1f5f9;font-size:.74rem"><span style="flex:1;font-family:monospace;color:#64748b">'+(li.part_number||'')+'</span><span style="flex:3">'+(li.description||li.item||'')+'</span><span style="width:40px;text-align:right">x'+(li.qty||0)+'</span><span style="width:58px;text-align:right">$'+parseFloat(li.cost||0).toFixed(2)+'</span><span style="width:64px;text-align:right;color:#1a3a6b;font-weight:600">$'+((parseFloat(li.qty||0)*parseFloat(li.cost||0))||0).toFixed(2)+'</span></div>';}).join('')+'</div>';}return '<div style="background:#fff;border-radius:10px;padding:14px;margin-bottom:10px;box-shadow:0 1px 4px rgba(0,0,0,.08)"><div style="display:flex;justify-content:space-between;align-items:flex-start"><div style="flex:1"><div style="font-weight:600;font-size:.85rem">Invoice #'+(inv.invoice_number||i+1)+' — '+(inv.vendor||'Unknown')+'</div><div style="color:#64748b;font-size:.78rem">'+(inv.invoice_date||inv.date||'')+' | Total: $'+(parseFloat(inv.total_amount||inv.total||0).toFixed(2))+'</div>'+lineHtml+tagHtml+'</div><div style="white-space:nowrap;margin-left:8px"><button style="'+BTN_E+'" onclick="partsInvoiceForm('+(i)+')">Edit</button><button style="'+BTN_D+'" onclick="partsDelInvoice('+(i)+')">Del</button></div></div></div>';}var html='<div style="padding:14px"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px"><span style="font-weight:700;font-size:.95rem">Parts Invoices</span><div><button style="'+BTN_S+';margin-right:6px" onclick="partsScanInvoice()">Scan Invoice</button><button style="'+BTN_P+'" onclick="partsInvoiceForm(-1)">+ Add</button></div></div>';html+='<input type="text" id="inv-search" placeholder="Search vendor, invoice #, or tags..." style="'+INP+'" oninput="partsSearchInvoices(this.value)">';html+='<div id="inv-list">';if(!items.length)html+='<div style="text-align:center;color:#94a3b8;padding:30px 0">No invoices yet.</div>';else items.forEach(function(inv,i){html+=invCard(inv,i);});html+='</div></div>';panel.innerHTML=html;}
function partsSearchInvoices(q){var items=_partsData.invoices;var lo=(q||'').toLowerCase().trim();var f=lo?items.filter(function(inv){return (inv.vendor||'').toLowerCase().indexOf(lo)>=0||(inv.invoice_number||'').toLowerCase().indexOf(lo)>=0||(inv.tags||'').toLowerCase().indexOf(lo)>=0;}):items;var list=document.getElementById('inv-list');if(!list)return;if(!f.length){list.innerHTML='<div style="text-align:center;color:#94a3b8;padding:20px">No results</div>';return;}var html='';f.forEach(function(inv,i){var origIdx=items.indexOf(inv);var _li=inv.items||inv.line_items||[];var tagHtml='';if(inv.tags&&inv.tags.trim()){tagHtml='<div style="margin-top:4px">'+inv.tags.split(',').map(function(t){return t.trim();}).filter(Boolean).map(function(t){return '<span style="display:inline-block;background:#fef3c7;color:#92400e;padding:1px 7px;border-radius:10px;font-size:.7rem;margin-right:3px">'+t+'</span>';}).join('')+'</div>';}var liHtml='';if(_li.length){liHtml='<div style="margin-top:6px;font-size:.78rem;background:#f8fafc;border-radius:6px;padding:6px">'+_li.map(function(li){return '<div style="display:flex;gap:8px;padding:2px 0;border-bottom:1px solid #f1f5f9;font-size:.74rem"><span style="flex:1;font-family:monospace;color:#64748b">'+(li.part_number||'')+'</span><span style="flex:3">'+(li.description||li.item||'')+'</span><span style="width:40px;text-align:right">x'+(li.qty||0)+'</span><span style="width:58px;text-align:right">$'+parseFloat(li.cost||0).toFixed(2)+'</span><span style="width:64px;text-align:right;color:#1a3a6b;font-weight:600">$'+((parseFloat(li.qty||0)*parseFloat(li.cost||0))||0).toFixed(2)+'</span></div>';}).join('')+'</div>';}html+='<div style="background:#fff;border-radius:10px;padding:14px;margin-bottom:10px;box-shadow:0 1px 4px rgba(0,0,0,.08)"><div style="display:flex;justify-content:space-between;align-items:flex-start"><div style="flex:1"><div style="font-weight:600;font-size:.85rem">Invoice #'+(inv.invoice_number||origIdx+1)+' — '+(inv.vendor||'Unknown')+'</div><div style="color:#64748b;font-size:.78rem">'+(inv.invoice_date||inv.date||'')+' | Total: $'+(parseFloat(inv.total_amount||inv.total||0).toFixed(2))+'</div>'+liHtml+tagHtml+'</div><div style="white-space:nowrap;margin-left:8px"><button style="'+BTN_E+'" onclick="partsInvoiceForm('+(origIdx)+')">Edit</button><button style="'+BTN_D+'" onclick="partsDelInvoice('+(origIdx)+')">Del</button></div></div></div>';});list.innerHTML=html;}
function partsScanInvoice(){_scanLineCount=0;document.getElementById('parts-panel').innerHTML='<div style="padding:14px"><div style="display:flex;align-items:center;gap:8px;margin-bottom:14px"><button style="'+BTN+';background:#f1f5f9;color:#334155" onclick="partsShowTab(\'invoices\')">Back</button><span style="font-weight:700;font-size:.95rem">Scan Invoice</span></div><div style="background:#f8fafc;border:2px dashed #cbd5e1;border-radius:10px;padding:24px;text-align:center;margin-bottom:14px"><div style="font-weight:600;color:#334155;margin-bottom:4px">Upload Invoice Photo or Image</div><div style="color:#94a3b8;font-size:.78rem;margin-bottom:14px">AI will extract items, quantities and costs automatically</div><input type="file" id="inv-img-input" accept="image/*,application/pdf" style="display:none" onchange="partsRunScan(this)"><button style="'+BTN_P+'" onclick="document.getElementById(\'inv-img-input\').click()">Choose Photo or File</button></div><div id="scan-preview" style="display:none;text-align:center;margin-bottom:10px"><img id="scan-img" style="max-width:100%;max-height:180px;border-radius:8px;object-fit:contain"><div id="scan-status" style="color:#6366f1;font-weight:600;margin-top:6px;font-size:.85rem">Scanning...</div></div><div id="scan-results" style="display:none"><div style="font-weight:700;margin-bottom:8px;color:#1a3a6b;font-size:.88rem">Review and Edit Scanned Data</div><label style="font-size:.78rem;color:#64748b">Machine / Stock</label><select id="sc-mach" style="'+INP+'">'+machineTagOptions('')+'</select><label style="font-size:.75rem;color:#64748b">Tags (comma-separated)</label><input type="text" id="inv-tags" placeholder="e.g. pump, belt, urgent" style="'+INP+'"><label style="font-size:.75rem;color:#64748b">Vendor</label><input type="text" id="sc-vendor" style="'+INP+'"><label style="font-size:.75rem;color:#64748b">Invoice Number</label><input type="text" id="sc-invnum" style="'+INP+'"><label style="font-size:.75rem;color:#64748b">Date</label><input type="date" id="sc-date" style="'+INP+'"><div style="font-weight:600;font-size:.82rem;margin-bottom:6px;color:#334155">Line Items <button style="'+BTN+';background:#f1f5f9;color:#334155;padding:3px 8px;font-size:.72rem" onclick="partsAddScanLine(\'\',\'\',\'\',\'\')">+ Add Row</button></div><div id="scan-lines"></div><button style="'+BTN_P+';width:100%;margin-top:8px" onclick="partsSaveScanInvoice()">Save Invoice</button></div></div>';}
function partsRunScan(input){if(!input.files||!input.files[0])return;var file=input.files[0];var isPdf=file.type==='application/pdf'||(file.name&&file.name.toLowerCase().endsWith('.pdf'));var previewEl=document.getElementById('scan-preview');var statusEl=document.getElementById('scan-status');var resultsEl=document.getElementById('scan-results');previewEl.style.display='block';if(isPdf&&file.size>3*1024*1024){statusEl.textContent='PDF too large ('+(file.size/1024/1024).toFixed(1)+' MB). Max 3 MB for PDFs — take a photo of the invoice instead, or compress the PDF.';resultsEl.style.display='block';partsAddScanLine('','','','');return;}function parseAndShow(txt){var s=txt.indexOf('{'),e=txt.lastIndexOf('}');var cleaned=s>=0&&e>s?txt.substring(s,e+1):txt.trim();try{var parsed=JSON.parse(cleaned);statusEl.textContent='Scan complete! Review below.';resultsEl.style.display='block';document.getElementById('sc-vendor').value=parsed.vendor||'';document.getElementById('sc-invnum').value=parsed.invoice_number||'';document.getElementById('sc-date').value=parsed.date||'';var lines=parsed.line_items||[];lines.forEach(function(li){partsAddScanLine(li.part_number||'',li.description||li.item||'',li.qty,li.cost,li.use_type||'stock');});if(!lines.length)partsAddScanLine('','','','');}catch(err){statusEl.textContent='Could not parse. Enter manually.';resultsEl.style.display='block';partsAddScanLine('','','','');}}function doScan(b64,mime){statusEl.textContent='AI scanning invoice...';apiCall('POST','/api/ai',{image:b64,image_mime:mime}).then(function(d){parseAndShow(d.response||'');}).catch(function(e){var msg=(e&&e.message)||'unknown';if(msg.indexOf('Unexpected token')>=0||msg.indexOf('<!DOCTYPE')>=0||msg.indexOf('JSON')>=0)msg='File too large for upload. Use a photo instead of PDF, or compress further.';statusEl.textContent='Error: '+msg.substring(0,140);resultsEl.style.display='block';partsAddScanLine('','','','');});}var reader=new FileReader();reader.onload=function(e){var dataUrl=e.target.result;if(isPdf){doScan(dataUrl.split(',')[1],'application/pdf');return;}var img=new Image();img.onload=function(){var maxPx=1200,w=img.width,h=img.height;if(w>maxPx||h>maxPx){var r=Math.min(maxPx/w,maxPx/h);w=Math.round(w*r);h=Math.round(h*r);}var canvas=document.createElement('canvas');canvas.width=w;canvas.height=h;canvas.getContext('2d').drawImage(img,0,0,w,h);document.getElementById('scan-img').src=dataUrl;doScan(canvas.toDataURL('image/jpeg',0.7).split(',')[1],'image/jpeg');};img.src=dataUrl;};reader.readAsDataURL(file);}
function partsAddScanLine(partNumber,description,qty,cost,useType){var id='sl'+(++_scanLineCount),container=document.getElementById('scan-lines');if(!container)return;var ut=useType||'stock';var initTot=((parseFloat(qty)||0)*(parseFloat(cost)||0)).toFixed(2);var div=document.createElement('div');div.id=id;div.className='scan-line';div.style.cssText='display:flex;flex-direction:column;gap:4px;margin-bottom:8px;padding:6px;background:#f8fafc;border-radius:6px;border:1px solid #e2e8f0';var iS='padding:6px;border:1px solid #e2e8f0;border-radius:5px;font-size:.75rem;background:#fff';div.innerHTML='<div style="display:flex;gap:4px"><input class="scan-pn" type="text" placeholder="Part #" style="flex:1;'+iS+'" value="'+(partNumber||'')+'"><input class="scan-desc" type="text" placeholder="Description" style="flex:3;'+iS+'" value="'+(description||'')+'"></div><div style="display:flex;gap:4px;align-items:center"><input class="scan-qty" type="number" placeholder="Qty" step="1" style="width:60px;'+iS+'" value="'+(qty||'')+'" oninput="partsScanLineTotal(this.closest(\'.scan-line\'))"><input class="scan-cost" type="number" placeholder="Unit $" step="0.01" style="width:72px;'+iS+'" value="'+(cost||'')+'" oninput="partsScanLineTotal(this.closest(\'.scan-line\'))"><div class="scan-total" style="flex:1;padding:6px;font-size:.78rem;font-weight:600;color:#166534;text-align:right;background:#f0fdf4;border-radius:5px" title="Line total = qty × unit">$'+initTot+'</div><select class="scan-use" style="width:72px;padding:6px;border:1px solid #e2e8f0;border-radius:5px;font-size:.72rem;background:#fff" title="Stock = add to inventory. Used = consumed on arrival, not stocked."><option value="stock"'+(ut==='stock'?' selected':'')+'>Stock</option><option value="used"'+(ut==='used'?' selected':'')+'>Used</option></select><button onclick="this.closest(\'.scan-line\').remove()" style="padding:4px 8px;border-radius:5px;border:none;cursor:pointer;font-size:.8rem;background:#fee2e2;color:#b91c1c" title="Remove row">×</button></div>';container.appendChild(div);}
function partsScanLineTotal(row){if(!row)return;var q=parseFloat((row.querySelector('.scan-qty')||{}).value||0);var c=parseFloat((row.querySelector('.scan-cost')||{}).value||0);var t=row.querySelector('.scan-total');if(t)t.textContent='$'+(q*c).toFixed(2);}
function partsScanLinesData(){var lines=[],rows=document.getElementById('scan-lines').children;for(var i=0;i<rows.length;i++){var r=rows[i];var pn=((r.querySelector('.scan-pn')||{}).value||'').trim();var desc=((r.querySelector('.scan-desc')||{}).value||'').trim();var qty=parseFloat((r.querySelector('.scan-qty')||{}).value||0);var cost=parseFloat((r.querySelector('.scan-cost')||{}).value||0);var ut=((r.querySelector('.scan-use')||{}).value)||'stock';if(pn||desc)lines.push({part_number:pn,description:desc,qty:qty,cost:cost,total:qty*cost,use_type:ut});}return lines;}
function partsSaveScanInvoice(){var lines=partsScanLinesData();var total=lines.reduce(function(s,l){return s+(l.qty*l.cost);},0);var mVal=((document.getElementById('sc-mach')||{}).value)||'shop_stock';lines.forEach(function(l){l.machine_tag=mVal;});var payload={vendor:document.getElementById('sc-vendor').value,invoice_number:document.getElementById('sc-invnum').value,invoice_date:document.getElementById('sc-date').value,items:lines,total_amount:total,machine_tag:mVal,tags:((document.getElementById('inv-tags')||{}).value)||''};partsCheckAndSaveInvoice(payload,'add_invoice');}
function partsInvoiceForm(editIdx){_scanLineCount=0;var inv=editIdx>=0?_partsData.invoices[editIdx]:{};document.getElementById('parts-panel').innerHTML='<div style="padding:14px"><div style="display:flex;align-items:center;gap:8px;margin-bottom:14px"><button style="'+BTN+';background:#f1f5f9;color:#334155" onclick="partsShowTab(\'invoices\')">Back</button><span style="font-weight:700;font-size:.95rem">'+(editIdx>=0?'Edit Invoice':'Add Invoice')+'</span></div><label>Vendor</label><input type="text" id="sc-vendor" style="'+INP+'" value="'+(inv.vendor||'')+'"><label>Invoice Number</label><input type="text" id="sc-invnum" style="'+INP+'" value="'+(inv.invoice_number||'')+'"><label>Date</label><input type="date" id="sc-date" style="'+INP+'" value="'+(inv.date||inv.invoice_date||'')+'"><label style="font-size:.78rem;color:#64748b">Machine / Stock</label><select id="sc-mach" style="'+INP+'">'+machineTagOptions(inv.machine_tag||'')+'</select><label style="font-size:.78rem;color:#64748b">Tags (comma-separated)</label><input type="text" id="inv-tags" placeholder="e.g. pump, belt, urgent" style="'+INP+'" value="'+(inv.tags||'')+'"><div style="font-weight:600;font-size:.82rem;margin-bottom:6px">Line Items <button style="'+BTN+';background:#f1f5f9;color:#334155;padding:3px 8px;font-size:.72rem" onclick="partsAddScanLine(\'\',\'\',\'\',\'\')">+ Add Row</button></div><div id="scan-lines"></div><button style="'+BTN_P+';width:100%;margin-top:8px" onclick="partsSaveInvoiceEdit('+(editIdx)+')">Save Invoice</button></div>';var lines=inv.line_items||inv.items||[];lines.forEach(function(li){partsAddScanLine(li.part_number||'',li.description||li.item||'',li.qty,li.cost,li.use_type||'stock');});if(!lines.length)partsAddScanLine('','','','');}
function partsSaveInvoiceEdit(editIdx){var lines=partsScanLinesData();var total=lines.reduce(function(s,l){return s+(l.qty*l.cost);},0);var mVal=((document.getElementById('sc-mach')||{}).value)||'shop_stock';lines.forEach(function(l){l.machine_tag=mVal;});var payload={vendor:document.getElementById('sc-vendor').value,invoice_number:document.getElementById('sc-invnum').value,invoice_date:document.getElementById('sc-date').value,items:lines,total_amount:total,machine_tag:mVal,tags:((document.getElementById('inv-tags')||{}).value)||''};var action=editIdx>=0?'update_invoice':'add_invoice';if(editIdx>=0)payload.id=_partsData.invoices[editIdx].id;partsCheckAndSaveInvoice(payload,action);}
function partsCheckAndSaveInvoice(payload,action){function doSave(){apiCall('POST','/api/parts?action='+action,payload).then(function(){partsShowTab('invoices');}).catch(function(e){alert('Error: '+(e&&e.message?e.message:'unknown'));});}if(!payload.machine_tag||payload.machine_tag==='shop_stock'){doSave();return;}apiCall('POST','/api/manuals?action=check_invoice_parts',{items:payload.items,machine_tag:payload.machine_tag}).then(function(r){var flags=(r&&r.flags)||[];if(!flags.length){doSave();return;}partsShowInvoiceMismatchModal(flags,doSave);}).catch(function(){doSave();});}
function partsShowInvoiceMismatchModal(flags,onProceed){var rows=flags.map(function(f){var expected=(f.expected_machine_tags||[]).map(function(t){return machineTagLabel(t);}).join(' or ');return '<div style="padding:8px 10px;background:#fef3c7;border-radius:6px;margin-bottom:6px;font-size:.82rem"><div style="font-family:monospace;font-weight:700;color:#92400e">'+(f.part_number||'—')+'</div>'+(f.description?'<div style="color:#78350f;font-size:.78rem;margin-top:2px">'+f.description+'</div>':'')+'<div style="margin-top:3px;color:#78350f">According to the manual, this part belongs to '+expected+' — not the machine you picked.</div></div>';}).join('');var overlay=document.createElement('div');overlay.id='invchk-overlay';overlay.style.cssText='position:fixed;inset:0;background:rgba(0,0,0,.5);z-index:9999;display:flex;align-items:center;justify-content:center;padding:20px';overlay.innerHTML='<div style="background:#fff;border-radius:12px;padding:20px;max-width:520px;width:100%;max-height:80vh;overflow-y:auto;box-shadow:0 20px 60px rgba(0,0,0,.3)"><div style="font-weight:700;font-size:1rem;color:#92400e;margin-bottom:4px">⚠ Part / Machine Mismatch</div><div style="font-size:.82rem;color:#64748b;margin-bottom:12px">The following parts are listed in manuals for a different machine than the one you selected. Confirm before saving — or cancel and change the machine.</div>'+rows+'<div style="display:flex;gap:8px;justify-content:flex-end;margin-top:12px"><button style="'+BTN+';background:#f1f5f9;color:#334155" onclick="document.getElementById(\'invchk-overlay\').remove()">Cancel &amp; Fix</button><button style="'+BTN_P+'" id="invchk-proceed">Save Anyway</button></div></div>';document.body.appendChild(overlay);document.getElementById('invchk-proceed').onclick=function(){document.getElementById('invchk-overlay').remove();onProceed();};}
function partsDelInvoice(i){if(!confirm('Delete invoice?'))return;apiCall('POST','/api/parts?action=delete_invoice',{id:_partsData.invoices[i].id}).then(function(){partsShowTab('invoices');}).catch(function(){alert('Error');});}
function partsRenderManuals(){loadMachines();var panel=document.getElementById('parts-panel');var html='<div style="padding:14px"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px"><span style="font-weight:700;font-size:.95rem">Machine Manuals</span><div><button style="'+BTN_S+';margin-right:6px" onclick="partsShowPartSearch()">Part # Search</button><button style="'+BTN_P+'" onclick="partsUploadManualForm()">+ Upload Manual</button></div></div><div id="manual-search-panel" style="display:none"></div><div id="manuals-list"></div></div>';panel.innerHTML=html;partsRenderManualsList();}
function partsRenderManualsList(){var items=_partsData.manuals||[];var list=document.getElementById('manuals-list');if(!list)return;if(!items.length){list.innerHTML='<div style="text-align:center;color:#94a3b8;padding:30px 0">No manuals uploaded yet. Click <strong>+ Upload Manual</strong> to scan your first one.</div>';return;}list.innerHTML=items.map(function(m,i){var tag=m.machine_tag||'';var pc=parseInt(m.part_count)||0;var date=m.created_at?(new Date(m.created_at)).toLocaleDateString():'';var sizeMB=m.file_size_bytes?' · '+(parseInt(m.file_size_bytes)/1024/1024).toFixed(1)+' MB':'';var hasFile=!!(m.file_url||m.cloudinary_public_id);var missingFileBadge=hasFile?'':' <span style="background:#fee2e2;color:#dc2626;padding:1px 6px;border-radius:8px;font-size:.66rem;font-weight:600">NO FILE</span>';var statusBadge='';var es=m.extraction_status;if((es==='pending'||!es)&&pc>0)es='done';else if(!es)es=pc>0?'done':null;if(es==='pending'||es==='processing')statusBadge=' <span onclick="partsShowExtractionLog(\''+m.id+'\')" style="background:#dbeafe;color:#1e40af;padding:1px 6px;border-radius:8px;font-size:.66rem;font-weight:600;cursor:pointer" title="Click for progress log">EXTRACTING...</span>';else if(es==='failed')statusBadge=' <span onclick="partsShowExtractionLog(\''+m.id+'\')" style="background:#fee2e2;color:#dc2626;padding:1px 6px;border-radius:8px;font-size:.66rem;font-weight:600;cursor:pointer" title="Click to see why it failed">FAILED</span>';else if(es==='partial')statusBadge=' <span onclick="partsShowExtractionLog(\''+m.id+'\')" style="background:#fef3c7;color:#92400e;padding:1px 6px;border-radius:8px;font-size:.66rem;font-weight:600;cursor:pointer" title="Click to see which chunks had errors">PARTIAL</span>';return '<div style="'+CARD+'"><div style="font-weight:600;font-size:.9rem">'+(m.title||'Untitled')+missingFileBadge+statusBadge+'</div><div style="margin-top:4px">'+machineTagLabel(tag)+' <span style="color:#64748b;font-size:.78rem">· '+pc+' part'+(pc===1?'':'s')+' indexed · '+date+sizeMB+'</span></div>'+(m.notes?'<div style="color:#94a3b8;font-size:.75rem;margin-top:3px">'+m.notes+'</div>':'')+'<div style="display:flex;flex-wrap:wrap;gap:5px;margin-top:8px"><button style="'+BTN_S+'" onclick="partsViewManual('+i+')" title="Open the PDF">View</button><button style="'+BTN_A+'" onclick="partsShowManualParts('+i+')" title="Browse indexed parts">Parts ('+pc+')</button>'+(m.file_url?'<button style="'+BTN_A+'" onclick="partsReindexManual('+i+')" title="Re-run AI extraction">Reindex</button>':'')+'<button style="'+BTN_E+'" onclick="partsManualForm('+i+')">Edit</button><button style="'+BTN_D+'" onclick="partsDelManual('+i+')">Del</button></div></div>';}).join('');}
function partsViewManual(i,page){var m=_partsData.manuals[i];if(!m){alert('No manual');return;}if(!m.file_url&&!m.cloudinary_public_id){alert('No file attached to this manual. Re-upload it with a PDF.');return;}var hash=page?'#page='+parseInt(page):'';function openUrl(url){if(!url){alert('Could not resolve PDF URL');return;}window.open(url+hash,'_blank');}if(m.cloudinary_public_id){apiCall('POST','/api/manuals?action=get_download_url',{public_id:m.cloudinary_public_id}).then(function(r){openUrl((r&&r.url)||m.file_url||'');}).catch(function(){if(m.file_url)openUrl(m.file_url);else alert('Could not get signed URL');});}else{openUrl(m.file_url);}}
function partsReindexManual(i){var m=_partsData.manuals[i];if(!m)return;if(!m.file_url){alert('No stored file to reindex. Delete and re-upload the manual.');return;}if(!confirm('Re-run AI extraction on "'+(m.title||'this manual')+'"? Existing indexed parts will be replaced. Runs in the background — you\'ll see progress.'))return;apiCall('POST','/api/manuals?action=reindex_manual',{id:m.id}).then(function(r){var mid=r.poll_manual_id||m.id;var panel=document.getElementById('parts-panel');if(panel){panel.innerHTML='<div style="padding:14px"><div style="display:flex;align-items:center;gap:8px;margin-bottom:14px"><button style="'+BTN+';background:#f1f5f9;color:#334155" onclick="partsShowTab(\'manuals\')">Back</button><span style="font-weight:700;font-size:.95rem">Reindexing: '+(m.title||'Manual').replace(/</g,'&lt;')+'</span></div><div id="mf-status" style="margin:10px 0;font-size:.82rem;color:#64748b"></div></div>';partsPollManualStatus(mid,document.getElementById('mf-status'));}}).catch(function(e){alert('Error: '+(e&&e.message?e.message:'unknown'));});}
function partsUploadManualForm(){loadMachines();document.getElementById('parts-panel').innerHTML='<div style="padding:14px"><div style="display:flex;align-items:center;gap:8px;margin-bottom:14px"><button style="'+BTN+';background:#f1f5f9;color:#334155" onclick="partsShowTab(\'manuals\')">Back</button><span style="font-weight:700;font-size:.95rem">Upload Machine Manual</span></div><div style="background:#f0f7ff;border-left:3px solid #3b82f6;border-radius:6px;padding:10px 12px;margin-bottom:14px;font-size:.78rem;color:#1e40af">Upload a parts manual PDF. AI reads the parts list and indexes every part number against the machine you pick below. After that, scanning or entering invoices for other machines will warn you if the part number actually belongs on this one.<br><br><strong>Max 20 MB PDF.</strong> Files upload directly to secure Cloudinary storage, then the server pulls it back for AI extraction.</div><label style="font-size:.78rem;color:#64748b">Manual Title</label><input type="text" id="mf-title" placeholder="e.g. Flavor Injector Parts Manual rev 5" style="'+INP+'"><label style="font-size:.78rem;color:#64748b">Machine</label><select id="mf-machine" style="'+INP+'">'+machineTagOptions('')+'</select><label style="font-size:.78rem;color:#64748b">External URL (optional)</label><input type="url" id="mf-url" placeholder="Link to full PDF in Google Drive, etc." style="'+INP+'"><label style="font-size:.78rem;color:#64748b">Notes (optional)</label><textarea id="mf-notes" style="'+INP+';resize:vertical;height:50px" placeholder="Any context"></textarea><label style="font-size:.78rem;color:#64748b">PDF File</label><input type="file" id="mf-file" accept="application/pdf" style="'+INP+'"><div id="mf-status" style="margin:10px 0;font-size:.82rem;color:#64748b"></div><button style="'+BTN_P+';width:100%" onclick="partsRunManualUpload()">Upload &amp; Extract Parts</button></div>';}
function partsRunManualUpload(){var title=(document.getElementById('mf-title').value||'').trim();var machine=(document.getElementById('mf-machine')||{}).value||'';var fileInput=document.getElementById('mf-file');var url=(document.getElementById('mf-url').value||'').trim();var notes=(document.getElementById('mf-notes').value||'').trim();var status=document.getElementById('mf-status');if(!title){status.style.color='#dc2626';status.textContent='Title is required.';return;}status.style.color='#64748b';if(!fileInput.files||!fileInput.files[0]){status.textContent='Saving (metadata only)...';apiCall('POST','/api/manuals?action=save_manual_record',{title:title,machine_tag:machine,file_url:url,notes:notes}).then(function(){partsShowTab('manuals');}).catch(function(e){status.style.color='#dc2626';status.textContent='Error: '+(e&&e.message?e.message:'unknown');});return;}var file=fileInput.files[0];var maxMB=20;if(file.size>maxMB*1024*1024){status.style.color='#dc2626';status.textContent='File too large ('+(file.size/1024/1024).toFixed(1)+' MB). Max '+maxMB+' MB.';return;}status.innerHTML='<div class="spinner-wrap" style="display:inline-block;vertical-align:middle"><div class="spinner"></div></div> Preparing upload...';apiCall('GET','/api/manuals?action=get_upload_signature').then(function(sig){var fd=new FormData();fd.append('file',file);fd.append('api_key',sig.api_key);fd.append('timestamp',String(sig.timestamp));fd.append('signature',sig.signature);fd.append('folder',sig.folder);var xhr=new XMLHttpRequest();xhr.upload.onprogress=function(e){if(e.lengthComputable){var pct=Math.round((e.loaded/e.total)*100);status.innerHTML='<div style="display:flex;align-items:center;gap:8px"><div style="flex:1;background:#e2e8f0;border-radius:4px;height:8px;overflow:hidden"><div style="background:#3b82f6;height:100%;width:'+pct+'%;transition:width .15s"></div></div><span style="font-size:.78rem;color:#64748b">Uploading '+pct+'%</span></div>';}};xhr.onload=function(){if(xhr.status<200||xhr.status>=300){status.style.color='#dc2626';status.textContent='Cloudinary upload failed: '+xhr.status+' '+(xhr.responseText||'').slice(0,120);return;}var result;try{result=JSON.parse(xhr.responseText);}catch(e){status.style.color='#dc2626';status.textContent='Upload response invalid';return;}status.innerHTML='<div class="spinner-wrap" style="display:inline-block;vertical-align:middle"><div class="spinner"></div></div> Uploaded — AI extracting part numbers (30-90s)...';apiCall('POST','/api/manuals?action=save_manual_record',{title:title,machine_tag:machine,file_url:result.secure_url,cloudinary_public_id:result.public_id,file_size_bytes:result.bytes,filename:result.original_filename,notes:notes}).then(function(r){if(r.extraction_status==='none'){status.style.color='#166534';status.textContent='✓ Saved (no PDF to extract).';setTimeout(function(){partsShowTab('manuals');},1500);return;}var mid=r.poll_manual_id||(r.manual&&r.manual.id);if(!mid){status.style.color='#dc2626';status.textContent='Saved, but cannot track extraction — use Reindex from the Manuals tab.';setTimeout(function(){partsShowTab('manuals');},3000);return;}partsPollManualStatus(mid,status);}).catch(function(e){status.style.color='#dc2626';status.textContent='Extraction error: '+((e&&e.message)||'unknown').substring(0,180);});};xhr.onerror=function(){status.style.color='#dc2626';status.textContent='Upload network error.';};xhr.open('POST','https://api.cloudinary.com/v1_1/'+sig.cloud_name+'/raw/upload');xhr.send(fd);}).catch(function(e){status.style.color='#dc2626';status.textContent='Signature error: '+((e&&e.message)||'unknown');});}
function partsManualForm(editIdx){loadMachines();var m=editIdx>=0?_partsData.manuals[editIdx]:{};document.getElementById('parts-panel').innerHTML='<div style="padding:14px"><div style="display:flex;align-items:center;gap:8px;margin-bottom:14px"><button style="'+BTN+';background:#f1f5f9;color:#334155" onclick="partsShowTab(\'manuals\')">Back</button><span style="font-weight:700;font-size:.95rem">'+(editIdx>=0?'Edit':'Add')+' Manual (metadata)</span></div><div style="background:#fef3c7;border-left:3px solid #f59e0b;border-radius:6px;padding:8px 12px;margin-bottom:14px;font-size:.78rem;color:#92400e">To upload a new PDF and extract part numbers, use <strong>+ Upload Manual</strong> on the Manuals list.</div><input type="text" placeholder="Title" id="mf-t" style="'+INP+'" value="'+(m.title||'')+'"><label style="font-size:.78rem;color:#64748b">Machine</label><select id="mf-m" style="'+INP+'">'+machineTagOptions(m.machine_tag||'')+'</select><input type="url" placeholder="URL (optional)" id="mf-u" style="'+INP+'" value="'+(m.file_url||'')+'"><textarea placeholder="Notes" id="mf-n" style="'+INP+';resize:vertical;height:60px">'+(m.notes||'')+'</textarea><button style="'+BTN_P+';width:100%" onclick="partsSaveManualMetadata('+editIdx+')">Save</button></div>';}
function partsSaveManualMetadata(editIdx){if(editIdx<0){alert('Use + Upload Manual to create a new one.');return;}var data={id:_partsData.manuals[editIdx].id,title:document.getElementById('mf-t').value,machine_tag:document.getElementById('mf-m').value,file_url:document.getElementById('mf-u').value,notes:document.getElementById('mf-n').value};apiCall('POST','/api/manuals?action=save_manual_metadata',data).then(function(){partsShowTab('manuals');}).catch(function(e){alert('Error: '+(e&&e.message?e.message:'unknown'));});}
// Poll the manual's extraction status until it's done/failed, updating the UI as we go.
// Used by both the upload flow and the reindex flow so a slow extraction never blocks the browser.
// Shows the full extraction log for a manual in a modal so failed/partial extractions can be diagnosed.
function partsShowExtractionLog(manualId){apiCall('POST','/api/manuals?action=get_manual_status',{id:manualId}).then(function(m){var log=m.extraction_log||'(no log entries yet)';var lines=log.split('\n').filter(function(l){return l.trim();});var title=m.title||'Manual';var status=m.extraction_status||'unknown';var statusColor={done:'#166534',partial:'#d97706',failed:'#dc2626',pending:'#1e40af',processing:'#1e40af'}[status]||'#64748b';var body=lines.map(function(l){var isErr=/(failed|error)/i.test(l);return '<div style="font-family:monospace;font-size:.74rem;padding:4px 8px;border-bottom:1px solid #f1f5f9;color:'+(isErr?'#dc2626':'#334155')+'">'+l.replace(/</g,'&lt;')+'</div>';}).join('');var overlay=document.createElement('div');overlay.style.cssText='position:fixed;inset:0;background:rgba(0,0,0,.5);z-index:9999;display:flex;align-items:center;justify-content:center;padding:20px';overlay.innerHTML='<div style="background:#fff;border-radius:12px;padding:20px;max-width:760px;width:100%;max-height:85vh;overflow-y:auto;box-shadow:0 20px 60px rgba(0,0,0,.3)"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px"><div><div style="font-weight:700;font-size:1rem">'+title.replace(/</g,'&lt;')+'</div><div style="font-size:.78rem;color:'+statusColor+';font-weight:600;margin-top:2px">Status: '+status.toUpperCase()+' · '+(m.part_count||0)+' parts indexed</div></div><button onclick="this.closest(\'div[style*=position\').remove()" style="background:#f1f5f9;border:none;border-radius:6px;padding:6px 12px;cursor:pointer;font-size:.8rem">Close</button></div><div style="border:1px solid #e2e8f0;border-radius:8px;max-height:60vh;overflow-y:auto">'+(body||'<div style="padding:20px;text-align:center;color:#94a3b8">No log entries. This manual may have been extracted before logging was added.</div>')+'</div></div>';overlay.onclick=function(e){if(e.target===overlay)overlay.remove();};document.body.appendChild(overlay);}).catch(function(e){alert('Could not load log: '+(e&&e.message?e.message:'unknown'));});}
function partsPollManualStatus(manualId,statusEl){var pollCount=0;var maxPolls=120;function tick(){apiCall('POST','/api/manuals?action=get_manual_status',{id:manualId}).then(function(m){var s=m.extraction_status||'processing';var lastLine=((m.extraction_log||'').split('\n').filter(function(l){return l.trim();}).slice(-1)[0]||'').slice(25,220);if(s==='pending'||s==='processing'){statusEl.style.color='#64748b';statusEl.innerHTML='<div class="spinner-wrap" style="display:inline-block;vertical-align:middle"><div class="spinner"></div></div> Extracting parts in the background...'+(lastLine?'<div style="color:#94a3b8;font-size:.74rem;margin-top:4px">'+lastLine+'</div>':'');pollCount++;if(pollCount<maxPolls)setTimeout(tick,3000);else{statusEl.style.color='#dc2626';statusEl.textContent='Extraction taking longer than expected. Check the Manuals tab or click Reindex to retry.';}}else if(s==='done'||s==='partial'){statusEl.style.color=s==='partial'?'#d97706':'#166534';statusEl.innerHTML=(s==='partial'?'⚠ ':'✓ ')+'Extracted '+(m.part_count||0)+' part number'+(m.part_count===1?'':'s')+'.'+(lastLine?'<div style="color:#94a3b8;font-size:.74rem;margin-top:4px">'+lastLine+'</div>':'');setTimeout(function(){partsShowTab('manuals');},s==='partial'?4000:2500);}else{statusEl.style.color='#dc2626';statusEl.innerHTML='⚠ Extraction failed.'+(lastLine?'<div style="font-size:.74rem;margin-top:4px">'+lastLine+'</div>':'')+'<div style="margin-top:6px;font-size:.76rem">The manual was saved — click <strong>Reindex</strong> on its card in the Manuals tab to retry.</div>';}}).catch(function(){pollCount++;if(pollCount<15)setTimeout(tick,3000);else{statusEl.style.color='#dc2626';statusEl.textContent='Lost connection while tracking extraction. Refresh and check the Manuals tab.';}});}statusEl.style.color='#64748b';statusEl.innerHTML='<div class="spinner-wrap" style="display:inline-block;vertical-align:middle"><div class="spinner"></div></div> Upload complete. Starting background extraction...';setTimeout(tick,2500);}
function partsDelManual(i){if(!confirm('Delete this manual and all its indexed parts?'))return;apiCall('POST','/api/manuals?action=delete_manual',{id:_partsData.manuals[i].id}).then(function(){partsShowTab('manuals');}).catch(function(){alert('Error');});}
function partsShowPartSearch(){var panel=document.getElementById('manual-search-panel');if(!panel)return;panel.style.display='block';panel.innerHTML='<div style="background:#fff;border-radius:8px;padding:12px;margin-bottom:10px;box-shadow:0 1px 4px rgba(0,0,0,.08)"><div style="display:flex;gap:6px;margin-bottom:8px"><input type="text" id="mp-search" placeholder="Enter part number to look up..." style="flex:1;'+INP+';margin-bottom:0" oninput="partsDoPartSearch(this.value)"><button style="'+BTN+';background:#f1f5f9;color:#334155" onclick="partsHidePartSearch()">Close</button></div><div id="mp-search-results"></div></div>';setTimeout(function(){var inp=document.getElementById('mp-search');if(inp)inp.focus();},50);}
function partsHidePartSearch(){var panel=document.getElementById('manual-search-panel');if(panel){panel.style.display='none';panel.innerHTML='';}}
function partsDoPartSearch(q){clearTimeout(window._mpSearchTimer);var r=document.getElementById('mp-search-results');if(!q||q.length<2){if(r)r.innerHTML='';return;}window._mpSearchTimer=setTimeout(function(){apiCall('POST','/api/manuals?action=search_part',{query:q}).then(function(d){if(!r)return;var matches=(d&&d.matches)||[];if(!matches.length){r.innerHTML='<div style="color:#94a3b8;font-size:.82rem;padding:10px">No matches in any manual.</div>';return;}r.innerHTML=matches.map(function(m){var idx=_partsData.manuals.findIndex(function(x){return x.id===m.manual_id;});var page=m.page_number?parseInt(m.page_number):null;var openBtn='';if(idx>=0){openBtn=page?'<button style="'+BTN_S+';padding:3px 8px;font-size:.72rem;margin-left:8px" onclick="partsViewManual('+idx+','+page+')" title="Open PDF at page '+page+'">Open p.'+page+'</button>':'<button style="'+BTN+';padding:3px 8px;font-size:.72rem;margin-left:8px;background:#f1f5f9;color:#334155" onclick="partsViewManual('+idx+')" title="No page recorded, opens at start">Open</button>';}return '<div style="padding:6px 8px;background:#f8fafc;border-radius:6px;margin-bottom:4px;font-size:.82rem;display:flex;align-items:center;gap:6px"><div style="flex:1;min-width:0"><div style="font-family:monospace;font-weight:600;color:#1a3a6b">'+m.part_number+'</div><div style="color:#64748b;margin-top:2px;font-size:.76rem">'+(m.description||'(no description)')+' — '+machineTagLabel(m.machine_tag||'')+' · '+(m.manual_title||'Untitled manual')+(page?' · page '+page:'')+'</div></div>'+openBtn+'</div>';}).join('');}).catch(function(){});},250);}
function partsShowManualParts(i){var m=_partsData.manuals[i];if(!m)return;apiCall('POST','/api/manuals?action=get_manual_parts',{manual_id:m.id}).then(function(parts){parts=parts||[];window._mpCurrentParts=parts;window._mpCurrentIdx=i;var overlay=document.createElement('div');overlay.id='mp-overlay';overlay.style.cssText='position:fixed;inset:0;background:rgba(0,0,0,.5);z-index:9999;display:flex;align-items:center;justify-content:center;padding:20px';overlay.innerHTML='<div style="background:#fff;border-radius:12px;padding:16px;max-width:720px;width:100%;max-height:85vh;display:flex;flex-direction:column;box-shadow:0 20px 60px rgba(0,0,0,.3)"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px"><div style="font-weight:700">'+(m.title||'Manual')+' — <span id="mp-count">'+parts.length+'</span> parts</div><button style="'+BTN+';background:#f1f5f9;color:#334155" onclick="document.getElementById(\'mp-overlay\').remove()">Close</button></div><input type="text" id="mp-filter" placeholder="Filter within this manual: part #, description..." style="'+INP+';margin-bottom:10px" oninput="partsFilterManualParts(this.value)"><div id="mp-list" style="overflow-y:auto;flex:1"></div></div>';document.body.appendChild(overlay);partsFilterManualParts('');setTimeout(function(){var inp=document.getElementById('mp-filter');if(inp)inp.focus();},50);}).catch(function(e){alert('Error: '+(e&&e.message?e.message:'unknown'));});}
function partsFilterManualParts(q){var parts=window._mpCurrentParts||[];var idx=window._mpCurrentIdx;var m=_partsData.manuals[idx]||{};var hasFile=!!(m.file_url||m.cloudinary_public_id);var lo=(q||'').trim().toLowerCase();var filtered=lo?parts.filter(function(p){return (p.part_number||'').toLowerCase().indexOf(lo)>=0||(p.description||'').toLowerCase().indexOf(lo)>=0;}):parts;var countEl=document.getElementById('mp-count');if(countEl)countEl.textContent=filtered.length+(lo?' / '+parts.length:'');var list=document.getElementById('mp-list');if(!list)return;if(!filtered.length){list.innerHTML='<div style="color:#94a3b8;padding:20px;text-align:center">No parts match.</div>';return;}list.innerHTML=filtered.map(function(p){var page=p.page_number?parseInt(p.page_number):null;var btn='';if(hasFile){btn=page?'<button style="'+BTN_S+';padding:3px 8px;font-size:.72rem" onclick="partsViewManual('+idx+','+page+')" title="Open PDF at page '+page+'">p.'+page+'</button>':'<button style="'+BTN+';padding:3px 8px;font-size:.72rem;background:#f1f5f9;color:#94a3b8" onclick="partsViewManual('+idx+')" title="No page recorded">View</button>';}return '<div style="display:flex;align-items:center;gap:8px;padding:6px 8px;border-bottom:1px solid #f1f5f9;font-size:.82rem"><div style="flex:1;min-width:0"><div style="font-family:monospace;font-weight:600;color:#1a3a6b">'+p.part_number+'</div>'+(p.description?'<div style="color:#64748b;font-size:.74rem">'+p.description+'</div>':'')+'</div><div>'+btn+'</div></div>';}).join('');}
function partsRenderCrossRef(){var panel=document.getElementById('parts-panel');var prefill=window._crossRefPrefill||{};var pn=prefill.part_number||'';var desc=prefill.description||'';window._crossRefPrefill=null;var items=_partsData.crossref||[];panel.innerHTML='<div style="padding:14px"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px"><span style="font-weight:700;font-size:.95rem">Cross-Reference &amp; Price Lookup</span><button style="'+BTN_P+'" onclick="partsCrossRefForm(-1)">+ Add Mapping</button></div><div style="background:#fff;border-radius:10px;padding:14px;margin-bottom:12px;box-shadow:0 1px 4px rgba(0,0,0,.08)"><div style="font-weight:700;font-size:.88rem;margin-bottom:8px;color:#1a3a6b">🔍 Look up a part across vendors</div><div style="display:flex;gap:6px;margin-bottom:10px;flex-wrap:wrap"><input type="text" id="xr-pn" placeholder="Part number *" style="flex:1;min-width:140px;'+INP+';margin-bottom:0" value="'+(pn||'').replace(/"/g,'&quot;')+'"><input type="text" id="xr-desc" placeholder="Description (helps AI match)" style="flex:2;min-width:180px;'+INP+';margin-bottom:0" value="'+(desc||'').replace(/"/g,'&quot;')+'"><button style="'+BTN_P+'" onclick="partsRunVendorSearch()">Search</button></div><div id="xr-results"></div></div><div style="font-weight:600;font-size:.78rem;margin:12px 0 6px;color:#64748b;text-transform:uppercase;letter-spacing:.04em">Saved Cross-References (manual OEM mappings)</div><div id="xr-list"></div></div>';var xl=document.getElementById('xr-list');if(!items.length){xl.innerHTML='<div style="text-align:center;color:#94a3b8;padding:20px 0;font-size:.82rem">No saved cross-references yet.</div>';}else{xl.innerHTML=items.map(function(r,i){return '<div style="'+CARD+';padding:10px 14px"><div style="display:flex;justify-content:space-between;align-items:center"><div><div style="font-weight:600;font-size:.85rem">'+(r.our_part||'')+' → '+(r.oem_part||'')+'</div><div style="color:#64748b;font-size:.78rem">'+(r.oem_brand||'')+(r.notes?' — '+r.notes:'')+'</div></div><div><button style="'+BTN_E+'" onclick="partsCrossRefForm('+i+')">Edit</button><button style="'+BTN_D+'" onclick="partsDelCrossRef('+i+')">Del</button></div></div></div>';}).join('');}if(pn){partsRunVendorSearch();}}
function partsRunVendorSearch(){var pn=((document.getElementById('xr-pn')||{}).value||'').trim();var desc=((document.getElementById('xr-desc')||{}).value||'').trim();if(!pn){alert('Enter a part number');return;}var res=document.getElementById('xr-results');if(!res)return;_xrVendors=[];res.innerHTML='<div style="padding:12px;text-align:center;color:#64748b;font-size:.85rem"><div class="spinner-wrap" style="display:inline-block;vertical-align:middle"><div class="spinner"></div></div> Loading quick-browse vendor links...</div>';apiCall('POST','/api/parts?action=search_parts_web',{part_number:pn,description:desc}).then(function(r){var urls=[{name:'Google',url:r.search_url,icon:'🔍'},{name:'Amazon',url:r.amazon_url,icon:'📦'},{name:'eBay',url:r.ebay_url,icon:'🏷️'},{name:'Grainger',url:r.grainger_url,icon:'🛠️'},{name:'Motion Industries',url:r.motion_url,icon:'⚙️'}].filter(function(x){return x.url;});var pnE=pn.replace(/\\/g,"\\\\").replace(/'/g,"\\'");var dE=desc.replace(/\\/g,"\\\\").replace(/'/g,"\\'");var quickHtml='<div style="background:#f0f7ff;border-radius:8px;padding:10px 12px;margin-bottom:10px;font-size:.82rem;color:#1e40af">Looking up <strong style="font-family:monospace">'+pn+'</strong>'+(desc?' <span style="color:#475569">('+desc+')</span>':'')+'</div><div style="font-size:.72rem;color:#64748b;text-transform:uppercase;letter-spacing:.04em;margin-bottom:6px">Quick browse (manual)</div><div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(160px,1fr));gap:6px;margin-bottom:14px">'+urls.map(function(u){return '<a href="'+u.url+'" target="_blank" rel="noopener" style="background:#fff;border:1px solid #e2e8f0;border-radius:6px;padding:8px;text-decoration:none;color:#1a3a6b;font-size:.78rem;text-align:center">'+u.icon+' '+u.name+'</a>';}).join('')+'</div><div style="font-size:.72rem;color:#64748b;text-transform:uppercase;letter-spacing:.04em;margin-bottom:6px">AI price comparison &amp; quote emails</div><div id="xr-ai-results"><div style="padding:14px;background:#fff;border:1px solid #e2e8f0;border-radius:8px;text-align:center;color:#64748b;font-size:.82rem"><div class="spinner-wrap" style="display:inline-block;vertical-align:middle"><div class="spinner"></div></div> Claude is searching the web (30-90s). Finding vendors, prices, and contact emails...</div></div>';res.innerHTML=quickHtml;apiCall('POST','/api/parts?action=search_vendor_prices',{part_number:pn,description:desc}).then(function(ai){_xrVendors=(ai&&ai.vendors)||[];var aiBox=document.getElementById('xr-ai-results');if(!aiBox)return;if(!_xrVendors.length){aiBox.innerHTML='<div style="padding:12px;background:#fef3c7;border-radius:6px;color:#78350f;font-size:.82rem">AI search returned no matching vendors for this part. Try the manual browse links above, or refine the description.</div>';return;}aiBox.innerHTML='<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(240px,1fr));gap:10px">'+_xrVendors.map(function(v,i){var priceTxt=(typeof v.price==='number'&&v.price>0)?'$'+Number(v.price).toFixed(2):'<span style="color:#94a3b8;font-size:.78rem;font-weight:400">Price not shown</span>';var availBadge=v.available?'<span style="background:#dcfce7;color:#166534;padding:1px 6px;border-radius:10px;font-size:.66rem;font-weight:600">IN STOCK</span>':'<span style="background:#fee2e2;color:#991b1b;padding:1px 6px;border-radius:10px;font-size:.66rem;font-weight:600">CHECK STOCK</span>';var emailLine=v.contact_email?'<div style="font-size:.76rem;color:#334155;margin-bottom:6px;word-break:break-all">✉️ '+v.contact_email+'</div>':'<div style="font-size:.72rem;color:#94a3b8;margin-bottom:6px">No contact email found</div>';var quoteBtn=v.contact_email?'<button style="'+BTN_P+';width:100%;font-size:.78rem" onclick="partsRequestQuoteAI('+i+')">Request Quote</button>':'<button style="'+BTN+';width:100%;font-size:.78rem;background:#f1f5f9;color:#94a3b8;cursor:not-allowed" disabled title="No contact email found">Request Quote</button>';return '<div style="background:#fff;border:1px solid #e2e8f0;border-radius:8px;padding:12px"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px"><div style="font-weight:700;font-size:.88rem">'+(v.vendor||'Vendor')+'</div>'+availBadge+'</div><div style="font-size:1.3rem;font-weight:700;color:#166534;margin-bottom:4px">'+priceTxt+'</div>'+(v.vendor_note?'<div style="color:#64748b;font-size:.74rem;margin-bottom:6px">'+v.vendor_note+'</div>':'')+(v.url?'<div style="margin-bottom:6px"><a href="'+v.url+'" target="_blank" rel="noopener" style="color:#2563eb;font-size:.76rem;text-decoration:underline">🌐 View product page</a></div>':'')+emailLine+quoteBtn+'</div>';}).join('')+'</div>';}).catch(function(e){var aiBox=document.getElementById('xr-ai-results');if(!aiBox)return;aiBox.innerHTML='<div style="padding:12px;background:#fee2e2;color:#991b1b;border-radius:6px;font-size:.82rem">AI search failed: '+((e&&e.message)||'unknown').substring(0,200)+'<div style="margin-top:6px;color:#64748b;font-size:.74rem">Use the quick-browse links above to search manually.</div></div>';});}).catch(function(e){res.innerHTML='<div style="color:#dc2626;padding:12px">Search error: '+((e&&e.message)||'unknown')+'</div>';});}
function partsRequestQuoteAI(i){var v=_xrVendors[i];if(!v){alert('Vendor not found');return;}var to=(v.contact_email||'').trim();var subj=v.quote_email_subject||'Quote Request';var body=v.quote_email_body||'';window.open('mailto:'+to+'?subject='+encodeURIComponent(subj)+'&body='+encodeURIComponent(body),'_blank');}
function partsCrossRefForm(editIdx){var r=editIdx>=0?_partsData.crossref[editIdx]:{};document.getElementById('parts-panel').innerHTML='<div style="padding:14px"><div style="display:flex;align-items:center;gap:8px;margin-bottom:14px"><button style="'+BTN+';background:#f1f5f9;color:#334155" onclick="partsShowTab(\'crossref\')">Back</button><span style="font-weight:700;font-size:.95rem">'+(editIdx>=0?'Edit':'Add')+' Cross Ref</span></div><input type="text" placeholder="Our Part Number" id="rf-o" style="'+INP+'" value="'+(r.our_part||'')+'"><input type="text" placeholder="OEM Part Number" id="rf-p" style="'+INP+'" value="'+(r.oem_part||'')+'"><input type="text" placeholder="OEM Brand" id="rf-b" style="'+INP+'" value="'+(r.oem_brand||'')+'"><textarea placeholder="Notes" id="rf-n" style="'+INP+'resize:vertical;height:60px">'+(r.notes||'')+'</textarea><button style="'+BTN_P+';width:100%" onclick="partsSaveCrossRef('+editIdx+')">Save</button></div>';}
function partsSaveCrossRef(editIdx){var data={our_part:document.getElementById('rf-o').value,oem_part:document.getElementById('rf-p').value,oem_brand:document.getElementById('rf-b').value,notes:document.getElementById('rf-n').value};var action=editIdx>=0?'update_cross_ref':'add_cross_ref';if(editIdx>=0)data.id=_partsData.crossref[editIdx].id;apiCall('POST','/api/parts?action='+action,data).then(function(){partsShowTab('crossref');}).catch(function(){alert('Error');});}
function partsDelCrossRef(i){if(!confirm('Delete?'))return;apiCall('POST','/api/parts?action=delete_cross_ref',{id:_partsData.crossref[i].id}).then(function(){partsShowTab('crossref');}).catch(function(){alert('Error');});}
function partsRenderOrders(){var panel=document.getElementById('parts-panel'),items=_partsData.orders;var sc={pending:'background:#fef9c3;color:#854d0e',ordered:'background:#dbeafe;color:#1e40af',received:'background:#dcfce7;color:#166534',cancelled:'background:#fee2e2;color:#991b1b'};var html='<div style="padding:14px"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px"><span style="font-weight:700;font-size:.95rem">Parts Orders</span><button style="'+BTN_P+'" onclick="partsOrderForm(-1)">+ Add</button></div>';if(!items.length)html+='<div style="text-align:center;color:#94a3b8;padding:30px 0">No orders yet.</div>';else items.forEach(function(o,i){var status=(o.status||'pending');var canReceive=status!=='received'&&status!=='cancelled';html+='<div style="'+CARD+'"><div style="display:flex;justify-content:space-between;align-items:flex-start"><div style="flex:1"><div style="font-weight:600;font-size:.85rem">'+(o.part_number||'')+' - '+(o.description||'')+'</div><div style="color:#64748b;font-size:.78rem">Qty: '+(o.quantity||0)+' | '+(o.supplier||'')+(o.unit_cost?' | $'+parseFloat(o.unit_cost).toFixed(2)+'/unit':'')+'</div><div style="margin-top:5px"><span style="padding:2px 8px;border-radius:10px;font-size:.72rem;'+sc[status]+'">'+status+'</span></div></div><div style="white-space:nowrap;margin-left:8px">'+(canReceive?'<button style="'+BTN_P+';padding:3px 9px;font-size:.72rem;margin-right:5px" onclick="partsMarkReceived('+i+')" title="Confirm receipt and add to inventory">Receive</button>':'')+'<button style="'+BTN_E+'" onclick="partsOrderForm('+i+')">Edit</button><button style="'+BTN_D+'" onclick="partsDelOrder('+i+')">Del</button></div></div></div>';});html+='</div>';panel.innerHTML=html;}
function partsMarkReceived(i){var o=_partsData.orders[i];if(!o){alert('Order not found');return;}var orderedQty=parseInt(o.quantity)||1;var received=prompt('Quantity actually received\\n(ordered '+orderedQty+', enter the count you got):',orderedQty);if(received===null)return;var qty=parseInt(received);if(isNaN(qty)||qty<=0){alert('Enter a positive whole number');return;}if(!o.part_number){alert('This order has no part number — cannot add to inventory without one. Edit the order to add a part number first.');return;}apiCall('POST','/api/parts?action=receive_part',{order_id:o.id,parts:[{part_number:o.part_number,description:o.description||'',quantity:qty,unit_cost:o.unit_cost||0}]}).then(function(r){if(typeof toast==='function')toast('Received '+qty+' into inventory');partsShowTab('orders');}).catch(function(e){alert('Error: '+((e&&e.message)||'unknown'));});}
function partsOrderForm(editIdx){var o=editIdx>=0?_partsData.orders[editIdx]:{};document.getElementById('parts-panel').innerHTML='<div style="padding:14px"><div style="display:flex;align-items:center;gap:8px;margin-bottom:14px"><button style="'+BTN+';background:#f1f5f9;color:#334155" onclick="partsShowTab(\'orders\')">Back</button><span style="font-weight:700;font-size:.95rem">'+(editIdx>=0?'Edit':'Add')+' Order</span></div><input type="text" placeholder="Part Number" id="of-n" style="'+INP+'" value="'+(o.part_number||'')+'"><input type="text" placeholder="Description" id="of-d" style="'+INP+'" value="'+(o.description||'')+'"><input type="number" placeholder="Quantity" id="of-q" style="'+INP+'" value="'+(o.quantity||'')+'"><input type="text" placeholder="Supplier" id="of-s" style="'+INP+'" value="'+(o.supplier||'')+'"><select id="of-st" style="'+INP+'">'+['pending','ordered','received','cancelled'].map(function(s){return '<option value="'+s+'"'+(o.status===s?' selected':'')+'>'+s.charAt(0).toUpperCase()+s.slice(1)+'</option>';}).join('')+'</select><textarea placeholder="Notes" id="of-no" style="'+INP+'resize:vertical;height:60px">'+(o.notes||'')+'</textarea><button style="'+BTN_P+';width:100%" onclick="partsSaveOrder('+editIdx+')">Save</button></div>';}
function partsSaveOrder(editIdx){var data={part_number:document.getElementById('of-n').value,description:document.getElementById('of-d').value,quantity:document.getElementById('of-q').value,supplier:document.getElementById('of-s').value,status:document.getElementById('of-st').value,notes:document.getElementById('of-no').value};var action=editIdx>=0?'update_parts_order':'add_parts_order';if(editIdx>=0)data.id=_partsData.orders[editIdx].id;apiCall('POST','/api/parts?action='+action,data).then(function(){partsShowTab('orders');}).catch(function(){alert('Error');});}
function partsDelOrder(i){if(!confirm('Delete?'))return;apiCall('POST','/api/parts?action=delete_parts_order',{id:_partsData.orders[i].id}).then(function(){partsShowTab('orders');}).catch(function(){alert('Error');});}
function partsRenderMachines(){
  loadMachines();
  var panel=document.getElementById('parts-panel');
  // Fetch accurate per-machine counts from the server (union of parts_inventory and manual_part_index
  // so manuals whose parts were already in inventory from an earlier invoice still count correctly).
  panel.innerHTML='<div style="padding:14px;text-align:center;color:#94a3b8">Loading machines…</div>';
  apiCall('GET','/api/parts?action=get_machine_part_counts').then(function(rows){
    var counts={};
    (Array.isArray(rows)?rows:[]).forEach(function(r){counts[r.machine_tag]=parseInt(r.cnt)||0;});
    partsRenderMachinesInner(counts);
  }).catch(function(){
    // If the count call fails, still render the list — fall back to the old inventory-only count
    partsRenderMachinesInner(null);
  });
}
function partsRenderMachinesInner(serverCounts){
  var panel=document.getElementById('parts-panel');
  var html='<div style="padding:14px"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px"><span style="font-weight:700;font-size:.95rem">Machinery</span><button style="'+BTN_P+'" onclick="partsMachineForm(-1)">+ Add Machine</button></div>';
  if(!_machinesList.length){
    html+='<div style="text-align:center;color:#94a3b8;padding:30px 0">No machines yet. Add your first machine!</div>';
  } else {
    _machinesList.forEach(function(m,i){
      var pc;
      if(serverCounts && (m.id in serverCounts)) pc=serverCounts[m.id];
      else if(serverCounts) pc=0;
      else pc=(_partsData.inventory||[]).filter(function(p){return p.machine_tag===m.id;}).length;
      html+='<div style="'+CARD+'"><div style="display:flex;justify-content:space-between;align-items:flex-start;gap:12px"><div style="flex:1;min-width:0"><div style="font-weight:700;font-size:.9rem;color:#1a3a6b">'+m.name+'</div>';
      if(m.make||m.model||m.year) html+='<div style="color:#64748b;font-size:.78rem">'+[m.make,m.model,m.year].filter(Boolean).join(' - ')+'</div>';
      if(m.notes) html+='<div style="color:#94a3b8;font-size:.75rem">'+m.notes+'</div>';
      html+='<div style="font-size:.75rem;color:#6366f1;margin-top:3px">'+pc+' part'+(pc!==1?'s':'')+' assigned</div></div>';
      html+='<div style="display:flex;flex-direction:column;gap:4px;align-items:flex-end"><button style="'+BTN_A+';padding:4px 9px;font-size:.7rem;margin:0" onclick="partsSyncMachineParts(\''+m.id+'\')" title="Claim every part from manuals tagged to this machine into this machine\'s inventory">Sync from manuals</button><div style="display:flex;gap:4px"><button style="'+BTN_E+';margin:0" onclick="partsMachineForm('+i+')">Edit</button><button style="'+BTN_D+';margin:0" onclick="partsDelMachine('+i+')">Del</button></div></div>';
      html+='</div></div>';
    });
  }
  html+='</div>';
  panel.innerHTML=html;
}
function partsSyncMachineParts(machineId){
  var m=(_machinesList||[]).find(function(x){return x.id===machineId;});
  var machineName=m?(m.name||'machine'):'machine';
  if(!confirm('Assign every part from '+machineName+'\'s manuals to its inventory?\n\nThis updates parts whose machine is currently empty or Shop Stock. Parts already assigned to a different machine are left alone.'))return;
  apiCall('POST','/api/parts?action=sync_machine_parts',{machine_tag:machineId}).then(function(r){
    var n=r.updated||0;
    if(typeof toast==='function') toast('Synced: '+n+' part'+(n===1?'':'s')+' assigned to '+machineName);
    else alert('Synced '+n+' part'+(n===1?'':'s')+'.');
    // Invalidate inventory cache so the counts on this screen are fresh
    _partsData.inventory=[];
    partsRenderMachines();
  }).catch(function(e){alert('Sync failed: '+(e&&e.message?e.message:'unknown'));});
}
function partsMachineForm(editIdx){var m=editIdx>=0?_machinesList[editIdx]:{};document.getElementById('parts-panel').innerHTML='<div style="padding:14px"><div style="display:flex;align-items:center;gap:8px;margin-bottom:14px"><button style="'+BTN+';background:#f1f5f9;color:#334155" onclick="partsRenderMachines()">Back</button><span style="font-weight:700;font-size:.95rem">'+(editIdx>=0?'Edit':'Add')+' Machine</span></div><input type="text" placeholder="Machine Name (required)" id="mch-n" style="'+INP+'" value="'+(m.name||'')+'"><input type="text" placeholder="Make or Brand" id="mch-mk" style="'+INP+'" value="'+(m.make||'')+'"><input type="text" placeholder="Model" id="mch-mo" style="'+INP+'" value="'+(m.model||'')+'"><input type="text" placeholder="Year" id="mch-y" style="'+INP+'" value="'+(m.year||'')+'"><textarea placeholder="Notes (serial number, location, etc.)" id="mch-no" style="'+INP+'resize:vertical;height:60px">'+(m.notes||'')+'</textarea><button style="'+BTN_P+';width:100%" onclick="partsSaveMachine('+editIdx+')">Save Machine</button></div>';}
function partsSaveMachine(editIdx){var name=document.getElementById('mch-n').value.trim();if(!name){alert('Machine name required');return;}var machine={id:editIdx>=0?_machinesList[editIdx].id:'mach_'+Date.now(),name:name,make:document.getElementById('mch-mk').value,model:document.getElementById('mch-mo').value,year:document.getElementById('mch-y').value,notes:document.getElementById('mch-no').value};if(editIdx>=0)_machinesList[editIdx]=machine;else _machinesList.push(machine);saveMachines();partsRenderMachines();}
function partsDelMachine(i){if(!confirm('Delete this machine?'))return;_machinesList.splice(i,1);saveMachines();partsRenderMachines();}

// ═══ TROUBLESHOOT ══════════════════════════════════════════════════════════
// Conversation state: last diagnosis so the user can follow up with more detail
var _tsLastDiagnosis = null;

function partsRenderTroubleshoot() {
  loadMachines();
  // Preload manuals so the manual-picker dropdown has data. If the user has already
  // visited the Manuals tab it's cached; otherwise fetch.
  var ensureManuals = (Array.isArray(_partsData.manuals) && _partsData.manuals.length > 0)
    ? Promise.resolve(_partsData.manuals)
    : apiCall('GET', '/api/manuals?action=get_manuals').then(function(d){ _partsData.manuals = Array.isArray(d) ? d : []; return _partsData.manuals; }).catch(function(){ return []; });
  ensureManuals.then(function(){
    var panel = document.getElementById('parts-panel');
    if (!panel) return;
    var machineOptions = '<option value="">— Select a machine —</option>' + (_machinesList||[]).map(function(m){
      return '<option value="'+m.id+'">'+ (m.name||'Machine') + (m.make?' · '+m.make:'') + (m.model?' '+m.model:'') + '</option>';
    }).join('');
    panel.innerHTML =
      '<div style="padding:14px;max-width:780px;margin:0 auto">' +
        '<div style="display:flex;align-items:center;gap:10px;margin-bottom:10px">' +
          '<span style="font-weight:700;font-size:.95rem">🔧 Troubleshoot</span>' +
          '<span style="color:#64748b;font-size:.76rem">AI-assisted diagnosis using the machine\'s manual + web search</span>' +
        '</div>' +
        '<div style="background:#f0f7ff;border-left:3px solid #3b82f6;border-radius:6px;padding:10px 12px;margin-bottom:14px;font-size:.78rem;color:#1e40af">' +
          'Describe what\'s happening with the machine — strange noises, error codes, failed startup, product defects, anything. Claude reads the manual (if one is uploaded) and searches the web for known failure modes and service bulletins on this make/model, then gives you step-by-step diagnostic instructions.' +
        '</div>' +
        '<label style="font-size:.78rem;color:#64748b;display:block;margin-bottom:3px">Machine</label>' +
        '<select id="ts-machine" style="'+INP+'" onchange="partsTsOnMachineChange()">' + machineOptions + '</select>' +
        '<label style="font-size:.78rem;color:#64748b;display:block;margin-bottom:3px">Manual to reference <span style="color:#94a3b8">(optional — leave blank to use all manuals tagged to this machine)</span></label>' +
        '<select id="ts-manual" style="'+INP+'"><option value="">— Auto-pick from this machine\'s manuals —</option></select>' +
        '<label style="font-size:.78rem;color:#64748b;display:block;margin-bottom:3px">What\'s happening?</label>' +
        '<textarea id="ts-symptoms" style="'+INP+';resize:vertical;min-height:110px;font-family:inherit" placeholder="e.g. Machine starts normally but after ~2 minutes there\'s a high-pitched squeal from the back of the unit and product output becomes inconsistent. No error codes on the panel. Noise gets worse if we push speed past 60%."></textarea>' +
        '<div id="ts-status" style="margin:8px 0;font-size:.82rem;color:#64748b;min-height:20px"></div>' +
        '<div style="display:flex;gap:8px">' +
          '<button style="'+BTN_P+';flex:1" onclick="partsRunDiagnose()">🔎 Diagnose</button>' +
          '<button style="'+BTN+';background:#f1f5f9;color:#334155" onclick="partsRenderTroubleshoot()">Clear</button>' +
        '</div>' +
        '<div id="ts-result" style="margin-top:14px"></div>' +
      '</div>';
    // If we had a prior diagnosis, redraw it so tab-switching doesn't lose it
    if (_tsLastDiagnosis) {
      document.getElementById('ts-symptoms').value = _tsLastDiagnosis.symptoms || '';
      if (_tsLastDiagnosis.machine_tag) document.getElementById('ts-machine').value = _tsLastDiagnosis.machine_tag;
      partsTsOnMachineChange();
      if (_tsLastDiagnosis.manual_id) {
        // Set after dropdown rebuilt
        setTimeout(function(){ var s=document.getElementById('ts-manual'); if(s) s.value = _tsLastDiagnosis.manual_id; }, 30);
      }
      partsRenderDiagnosisResult(_tsLastDiagnosis.response);
    }
  });
}

// When the user picks a machine, rebuild the manual dropdown to show only manuals tagged to it.
function partsTsOnMachineChange() {
  var tag = (document.getElementById('ts-machine')||{}).value || '';
  var manuals = (_partsData.manuals || []).filter(function(m){
    if (!tag) return false;
    return (m.machine_tag || '') === tag;
  });
  var sel = document.getElementById('ts-manual');
  if (!sel) return;
  sel.innerHTML = '<option value="">— Auto-pick from this machine\'s manuals ('+manuals.length+' available) —</option>' +
    manuals.map(function(m){
      var parts = parseInt(m.part_count)||0;
      return '<option value="'+m.id+'">'+ (m.title||'Untitled') + ' · ' + parts + ' parts indexed</option>';
    }).join('');
}

function partsRunDiagnose() {
  var machineSel = document.getElementById('ts-machine');
  var manualSel = document.getElementById('ts-manual');
  var symptomsEl = document.getElementById('ts-symptoms');
  var status = document.getElementById('ts-status');
  var resultEl = document.getElementById('ts-result');
  var machine_tag = machineSel ? machineSel.value : '';
  var manual_id = manualSel ? manualSel.value : '';
  var symptoms = (symptomsEl ? symptomsEl.value : '').trim();
  if (!symptoms) { status.style.color = '#dc2626'; status.textContent = 'Describe the symptoms first.'; return; }
  if (!machine_tag) { status.style.color = '#d97706'; status.textContent = 'Pick a machine — AI needs to know which manual to reference.'; return; }
  status.style.color = '#64748b';
  status.innerHTML = '<div class="spinner-wrap" style="display:inline-block;vertical-align:middle"><div class="spinner"></div></div> Reading manual + searching the web for this issue... (30-90 seconds)';
  resultEl.innerHTML = '';
  apiCall('POST', '/api/troubleshoot?action=diagnose', { machine_tag: machine_tag, manual_id: manual_id, symptoms: symptoms })
    .then(function(r){
      status.textContent = '';
      _tsLastDiagnosis = { machine_tag: machine_tag, manual_id: manual_id, symptoms: symptoms, response: r };
      partsRenderDiagnosisResult(r);
    })
    .catch(function(e){
      status.style.color = '#dc2626';
      status.textContent = 'Diagnosis failed: ' + ((e && e.message) || 'unknown');
    });
}

function partsRenderDiagnosisResult(r) {
  var resultEl = document.getElementById('ts-result');
  if (!resultEl) return;
  if (!r || !r.diagnosis) {
    resultEl.innerHTML = '<div style="padding:20px;color:#dc2626">Empty response from AI. Click Diagnose to retry.</div>';
    return;
  }
  var d = r.diagnosis;
  var manualRefs = r.manual_refs || [];
  // Build a map from manual_id to index-in-_partsData.manuals for page-jump links
  var manualIndexById = {};
  (_partsData.manuals || []).forEach(function(m, i){ manualIndexById[m.id] = i; });
  // Helper: render a clickable page link. Page refs without a manual id fall back to the first attached manual.
  function pageLink(pageNum) {
    if (!pageNum) return '';
    var ref = manualRefs[0];
    if (!ref) return ' <span style="color:#94a3b8;font-size:.74rem">(p.'+pageNum+')</span>';
    var idx = manualIndexById[ref.id];
    if (idx === undefined) return ' <span style="color:#94a3b8;font-size:.74rem">(p.'+pageNum+')</span>';
    return ' <a href="#" onclick="partsViewManual('+idx+','+pageNum+');return false" style="color:#2563eb;font-size:.74rem;text-decoration:underline">📖 p.'+pageNum+'</a>';
  }
  function partLink(pn, desc) {
    if (!pn) return '';
    var safe = (pn || '').replace(/'/g, "\\'").replace(/</g, '&lt;');
    var descSafe = (desc || '').replace(/'/g, "\\'").replace(/</g, '&lt;');
    return '<a href="#" onclick="partsGotoCrossRefForPart(\''+safe+'\',\''+descSafe+'\');return false" style="font-family:monospace;color:#2563eb;font-weight:600;text-decoration:underline">'+pn+'</a>';
  }
  function esc(s) { return String(s||'').replace(/</g, '&lt;').replace(/>/g, '&gt;'); }
  var confidenceBadge = function(conf) {
    var colors = { high: ['#dcfce7','#166534'], medium: ['#fef3c7','#92400e'], low: ['#f1f5f9','#64748b'] };
    var c = colors[conf] || colors.low;
    return '<span style="background:'+c[0]+';color:'+c[1]+';padding:1px 6px;border-radius:8px;font-size:.66rem;font-weight:600;text-transform:uppercase;margin-left:6px">'+conf+'</span>';
  };
  var html = '<div style="background:#fff;border-radius:10px;box-shadow:0 1px 4px rgba(0,0,0,.08);overflow:hidden">';
  // Header
  html += '<div style="background:#1a3a6b;color:#fff;padding:12px 16px"><div style="font-weight:700;font-size:.95rem">Diagnosis — '+esc(r.machine_label||'')+'</div>';
  if (manualRefs.length > 0) {
    html += '<div style="font-size:.76rem;opacity:.85;margin-top:4px">Referenced '+manualRefs.length+' manual'+(manualRefs.length===1?'':'s')+': '+manualRefs.map(function(m){ return esc(m.title) + (m.trimmed ? ' (first 100 of '+m.totalPages+' pages)' : ''); }).join(' · ')+'</div>';
  } else {
    html += '<div style="font-size:.76rem;opacity:.85;margin-top:4px">No manual on file for this machine — diagnosis is based on web sources only.</div>';
  }
  html += '</div>';
  // Summary
  if (d.summary) {
    html += '<div style="padding:14px 16px;background:#f0f7ff;border-bottom:1px solid #e2e8f0;font-size:.88rem;color:#1e40af;line-height:1.5">'+esc(d.summary)+'</div>';
  }
  // Safety warnings
  if (Array.isArray(d.safety_warnings) && d.safety_warnings.length) {
    html += '<div style="padding:12px 16px;background:#fef2f2;border-bottom:1px solid #e2e8f0">' +
      '<div style="font-weight:700;font-size:.8rem;color:#991b1b;margin-bottom:6px">⚠️ Safety — do this FIRST</div>' +
      '<ul style="margin:0;padding-left:22px;font-size:.82rem;color:#7f1d1d;line-height:1.6">' +
      d.safety_warnings.map(function(s){ return '<li>'+esc(s)+'</li>'; }).join('') +
      '</ul></div>';
  }
  // Likely causes
  if (Array.isArray(d.likely_causes) && d.likely_causes.length) {
    html += '<div style="padding:12px 16px;border-bottom:1px solid #e2e8f0">' +
      '<div style="font-weight:700;font-size:.82rem;color:#334155;margin-bottom:8px">Likely Causes</div>' +
      d.likely_causes.map(function(c){
        return '<div style="background:#f8fafc;border-radius:8px;padding:10px;margin-bottom:6px">' +
          '<div style="font-weight:600;font-size:.85rem;color:#1a3a6b">'+esc(c.cause||'')+confidenceBadge(c.confidence||'low')+'</div>' +
          (c.reasoning ? '<div style="color:#64748b;font-size:.78rem;margin-top:4px">'+esc(c.reasoning)+'</div>' : '') +
          '</div>';
      }).join('') + '</div>';
  }
  // Diagnostic steps
  if (Array.isArray(d.diagnostic_steps) && d.diagnostic_steps.length) {
    html += '<div style="padding:12px 16px;border-bottom:1px solid #e2e8f0">' +
      '<div style="font-weight:700;font-size:.82rem;color:#334155;margin-bottom:8px">Diagnostic Steps</div>' +
      '<ol style="margin:0;padding-left:22px;font-size:.84rem;color:#334155;line-height:1.6">' +
      d.diagnostic_steps.map(function(s){
        var pg = s.manual_page ? pageLink(s.manual_page) : '';
        return '<li style="margin-bottom:8px"><div>'+esc(s.instruction||'')+pg+'</div>' +
          (s.expected_result ? '<div style="color:#64748b;font-size:.78rem;margin-top:2px">Expected: '+esc(s.expected_result)+'</div>' : '') +
          '</li>';
      }).join('') +
      '</ol></div>';
  }
  // Parts to check
  if (Array.isArray(d.parts_to_check) && d.parts_to_check.length) {
    html += '<div style="padding:12px 16px;border-bottom:1px solid #e2e8f0">' +
      '<div style="font-weight:700;font-size:.82rem;color:#334155;margin-bottom:8px">Parts to Inspect / Replace</div>' +
      '<div style="overflow-x:auto"><table style="width:100%;font-size:.78rem;border-collapse:collapse">' +
      '<thead><tr style="background:#f8fafc"><th style="padding:6px 10px;text-align:left;color:#64748b;font-weight:600">Part #</th><th style="padding:6px 10px;text-align:left;color:#64748b;font-weight:600">Name</th><th style="padding:6px 10px;text-align:left;color:#64748b;font-weight:600">Why</th><th style="padding:6px 10px;text-align:left;color:#64748b;font-weight:600">Manual</th></tr></thead><tbody>' +
      d.parts_to_check.map(function(p){
        return '<tr style="border-bottom:1px solid #f1f5f9"><td style="padding:6px 10px">'+partLink(p.part_number, p.name)+'</td><td style="padding:6px 10px">'+esc(p.name||'')+'</td><td style="padding:6px 10px;color:#64748b">'+esc(p.reason||'')+'</td><td style="padding:6px 10px">'+(p.manual_page ? pageLink(p.manual_page) : '<span style="color:#94a3b8">—</span>')+'</td></tr>';
      }).join('') +
      '</tbody></table></div></div>';
  }
  // Web findings
  if (Array.isArray(d.web_findings) && d.web_findings.length) {
    html += '<div style="padding:12px 16px;border-bottom:1px solid #e2e8f0">' +
      '<div style="font-weight:700;font-size:.82rem;color:#334155;margin-bottom:8px">🌐 Web Sources</div>' +
      d.web_findings.map(function(w){
        var href = String(w.url||'').trim();
        var hrefSafe = href ? href.replace(/"/g, '&quot;') : '';
        return '<div style="background:#f8fafc;border-radius:8px;padding:8px 10px;margin-bottom:5px">' +
          (hrefSafe ? '<a href="'+hrefSafe+'" target="_blank" rel="noopener" style="color:#2563eb;font-weight:600;font-size:.82rem;text-decoration:underline">'+esc(w.title||href)+'</a>' : '<span style="font-weight:600;font-size:.82rem">'+esc(w.title||'')+'</span>') +
          (w.summary ? '<div style="color:#64748b;font-size:.76rem;margin-top:2px">'+esc(w.summary)+'</div>' : '') +
          '</div>';
      }).join('') + '</div>';
  }
  // Next actions
  if (Array.isArray(d.next_actions) && d.next_actions.length) {
    html += '<div style="padding:12px 16px">' +
      '<div style="font-weight:700;font-size:.82rem;color:#334155;margin-bottom:8px">Next Actions</div>' +
      '<ul style="margin:0;padding-left:22px;font-size:.84rem;color:#334155;line-height:1.6">' +
      d.next_actions.map(function(a){ return '<li>'+esc(a)+'</li>'; }).join('') +
      '</ul></div>';
  }
  html += '</div>';
  resultEl.innerHTML = html;
}
